window.AIDA_DATA.itemSpecificContexts = {"metadata":{"policy":"item-specific-only","notes":["No learner-facing runtime sentence generator is used.","Japanese grammar uses manually audited examples or conservative authentic-corpus matches that pass token-boundary and English-meaning checks.","Ambiguous grammar points without a trustworthy match intentionally show no sentence example instead of a possibly wrong one.","Cantonese grammar examples come from manually audited overrides.","Everyday supplement vocabulary examples are authored for the exact item rather than produced by a shared slot template.","Multi-sentence study material comes only from curated reading banks; independent sentence examples are never stitched together.","All N5 Japanese grammar cards have at least one manually audited or high-confidence item-specific example in V14."]},"japanese":{"vocabulary":{"jp-ev-0001":[{"text":"カレー用の人参を薄く切った。","translation":"I sliced the carrots thinly for the curry.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0002":[{"text":"玉ねぎを炒めたら、台所がいい匂いになった。","translation":"When I sautéed the onion, the kitchen started to smell good.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0003":[{"text":"とんかつに千切りキャベツを添えた。","translation":"I served shredded cabbage with the tonkatsu.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0004":[{"text":"じゃがいもが柔らかくなるまで煮てください。","translation":"Please simmer the potatoes until they are tender.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0005":[{"text":"焼きいもにするためにさつまいもを買った。","translation":"I bought a sweet potato to make roasted sweet potato.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0006":[{"text":"大根をおでんに入れると、だしの味がよく染みる。","translation":"When you put daikon in oden, it absorbs the broth well.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0007":[{"text":"白菜と豚肉で鍋を作った。","translation":"I made a hot pot with Chinese cabbage and pork.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0008":[{"text":"ほうれん草をゆでて、おひたしにした。","translation":"I boiled the spinach and made ohitashi.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0009":[{"text":"サンドイッチにレタスをたっぷり入れた。","translation":"I put plenty of lettuce in the sandwich.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0010":[{"text":"きゅうりを薄く切ってサラダに入れた。","translation":"I sliced the cucumber thinly and added it to the salad.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0011":[{"text":"完熟したトマトをそのまま食べた。","translation":"I ate a fully ripe tomato as it was.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0012":[{"text":"なすを焼くと、中がとても柔らかくなる。","translation":"Eggplant becomes very soft inside when you grill it.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0013":[{"text":"ピーマンの肉詰めを夕飯に作った。","translation":"I made stuffed green peppers for dinner.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0014":[{"text":"赤いパプリカを細切りにして炒めた。","translation":"I sliced the red bell pepper into thin strips and stir-fried it.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0015":[{"text":"ブロッコリーを少し固めにゆでた。","translation":"I boiled the broccoli so that it stayed slightly firm.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0016":[{"text":"カリフラワーをオーブンで焼いた。","translation":"I roasted the cauliflower in the oven.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0017":[{"text":"かぼちゃの煮物を作った。","translation":"I made simmered pumpkin.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0018":[{"text":"夏祭りで焼きとうもろこしを食べた。","translation":"I ate grilled corn at the summer festival.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0019":[{"text":"長ねぎを刻んでラーメンにのせた。","translation":"I chopped the green onion and put it on the ramen.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0020":[{"text":"にんにくを入れすぎて、手に匂いが残った。","translation":"I used too much garlic, and the smell stayed on my hands.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0021":[{"text":"しょうがをすって紅茶に入れた。","translation":"I grated some ginger and put it in my tea.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0022":[{"text":"きのこを何種類か入れてパスタを作った。","translation":"I made pasta with several kinds of mushrooms.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0023":[{"text":"干ししいたけを水で戻してから煮物に使った。","translation":"I rehydrated the dried shiitake mushrooms before using them in a simmered dish.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0024":[{"text":"えのきを鍋に入れる前に根元を切った。","translation":"I cut off the base of the enoki mushrooms before putting them in the hot pot.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0025":[{"text":"もやしは火を通しすぎないほうが食感がいい。","translation":"Bean sprouts have a better texture if you do not overcook them.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0026":[{"text":"ごぼうをささがきにしてきんぴらを作った。","translation":"I shaved the burdock root into thin pieces and made kinpira.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0027":[{"text":"れんこんを切ると、穴がきれいに並んでいる。","translation":"When you cut lotus root, you can see its holes arranged neatly.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0028":[{"text":"オクラをゆでて納豆に混ぜた。","translation":"I boiled the okra and mixed it with natto.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0029":[{"text":"ビールのおつまみに枝豆を注文した。","translation":"I ordered edamame as a snack with beer.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0030":[{"text":"セロリの香りが苦手な人もいる。","translation":"Some people do not like the smell of celery.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0031":[{"text":"アイスを冷凍庫に入れておいた。","translation":"I put the ice cream in the freezer.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0032":[{"text":"冷めたご飯を電子レンジで温めた。","translation":"I reheated the cold rice in the microwave.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0033":[{"text":"炊飯器の予約を朝七時に設定した。","translation":"I set the rice cooker timer for seven in the morning.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0034":[{"text":"電気ケトルでお湯を沸かしてコーヒーを入れた。","translation":"I boiled water in the electric kettle and made coffee.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0035":[{"text":"生肉を切ったまな板はすぐに洗った。","translation":"I washed the cutting board immediately after cutting raw meat on it.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0036":[{"text":"おたまでスープを器によそった。","translation":"I ladled the soup into a bowl.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0037":[{"text":"揚げ物を菜箸でそっと返した。","translation":"I gently turned the fried food with cooking chopsticks.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0038":[{"text":"缶切りが見つからなくて、缶を開けられなかった。","translation":"I could not open the can because I could not find the can opener.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0039":[{"text":"この瓶は栓抜きがないと開けられない。","translation":"This bottle cannot be opened without a bottle opener.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0040":[{"text":"残ったカレーを保存容器に入れて冷蔵庫にしまった。","translation":"I put the leftover curry in a food storage container and stored it in the refrigerator.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0041":[{"text":"使ったティッシュをゴミ箱に捨てた。","translation":"I threw the used tissue in the trash can.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0042":[{"text":"週末にリビングへ掃除機をかける。","translation":"I vacuum the living room on weekends.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0043":[{"text":"洗濯機を回している間に朝ご飯を作った。","translation":"I made breakfast while the washing machine was running.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0044":[{"text":"雨の日は乾燥機を使うことが多い。","translation":"I often use the clothes dryer on rainy days.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0045":[{"text":"洗ったシャツを物干し竿にかけた。","translation":"I hung the washed shirts on the clothesline pole.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0046":[{"text":"ハムスターが夜になると回し車で走り始める。","translation":"The hamster starts running on its wheel at night.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0047":[{"text":"モルモットに野菜を少しあげた。","translation":"I gave the guinea pig a little bit of vegetables.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0048":[{"text":"池の石の上で亀が日向ぼっこしていた。","translation":"A turtle was basking in the sun on a rock in the pond.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0049":[{"text":"雨上がりに庭で蛙の鳴き声が聞こえた。","translation":"After the rain, I could hear frogs calling in the garden.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0050":[{"text":"山道で蛇を見かけて、少し遠回りした。","translation":"I saw a snake on the mountain path, so I took a slight detour.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0051":[{"text":"石の上でトカゲが日光を浴びていた。","translation":"A lizard was basking in the sun on a rock.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0052":[{"text":"蜂が近くを飛んできたので、静かにその場を離れた。","translation":"A bee flew close to me, so I quietly moved away.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0053":[{"text":"砂糖の近くに蟻が集まっていた。","translation":"Ants had gathered near the sugar.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0054":[{"text":"窓を開けたら蝿が一匹入ってきた。","translation":"When I opened the window, a fly came in.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0055":[{"text":"台所でゴキブリを見つけてびっくりした。","translation":"I was startled when I found a cockroach in the kitchen.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0056":[{"text":"駅前の広場に鳩がたくさんいた。","translation":"There were many pigeons in the square in front of the station.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0057":[{"text":"池でアヒルが泳いでいた。","translation":"A duck was swimming in the pond.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0058":[{"text":"朝早く鶏の鳴き声で目が覚めた。","translation":"I woke up early in the morning to the sound of a chicken crowing.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0059":[{"text":"農場で子豚を見た。","translation":"I saw a piglet at the farm.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0060":[{"text":"丘の上で羊が草を食べていた。","translation":"Sheep were eating grass on the hill.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0061":[{"text":"近所の買い物にはスクーターで行くことがある。","translation":"I sometimes take a scooter when I shop nearby.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0062":[{"text":"引っ越しの荷物をバンに積んだ。","translation":"I loaded the moving boxes into the van.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0063":[{"text":"島までフェリーで二時間かかった。","translation":"It took two hours to reach the island by ferry.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0064":[{"text":"救急車が来たので、車を道の端に寄せた。","translation":"An ambulance was coming, so I pulled the car to the side of the road.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0065":[{"text":"サイレンを鳴らした消防車が交差点を通った。","translation":"A fire engine with its siren on passed through the intersection.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0066":[{"text":"スマートフォンの充電がもう十パーセントしかない。","translation":"My smartphone only has ten percent battery left.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0067":[{"text":"充電器を家に忘れてきた。","translation":"I left my charger at home.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0068":[{"text":"USBケーブルでパソコンとカメラをつないだ。","translation":"I connected the computer and camera with a USB cable.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0069":[{"text":"夜はヘッドホンで音楽を聞く。","translation":"I listen to music with headphones at night.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0070":[{"text":"電車ではイヤホンの音量を下げている。","translation":"I keep the volume on my earphones low on the train.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0071":[{"text":"テレビのリモコンがソファの下に落ちていた。","translation":"The TV remote had fallen under the sofa.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0072":[{"text":"旅行にはモバイルバッテリーを持っていく。","translation":"I take a power bank with me when I travel.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0073":[{"text":"キーボードにコーヒーをこぼしそうになった。","translation":"I almost spilled coffee on the keyboard.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0074":[{"text":"マウスの電池を交換した。","translation":"I replaced the battery in the computer mouse.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0075":[{"text":"三か月使った歯ブラシを新しいものに替えた。","translation":"I replaced the toothbrush I had used for three months with a new one.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0076":[{"text":"歯磨き粉がもう少ししか残っていない。","translation":"There is only a little toothpaste left.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0077":[{"text":"シャンプーが目に入って痛かった。","translation":"Shampoo got in my eyes and it hurt.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0078":[{"text":"髪が乾燥するのでコンディショナーを使っている。","translation":"I use conditioner because my hair gets dry.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0079":[{"text":"旅行用の小さいボディソープを買った。","translation":"I bought a small bottle of body wash for traveling.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0080":[{"text":"鼻をかむためにティッシュを一枚取った。","translation":"I took a tissue to blow my nose.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0081":[{"text":"トイレットペーパーが切れそうだから買っておこう。","translation":"We are almost out of toilet paper, so I should buy some.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0082":[{"text":"古いカミソリは切れ味が悪くなっていた。","translation":"The old razor had become dull.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"jp-ev-0083":[{"text":"髪を乾かすのにドライヤーを使った。","translation":"I used a hair dryer to dry my hair.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}]},"grammar":{"jp-g-0001":[{"text":"これは私の本だ。","translation":"This is my book.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼は大学生だ。","translation":"He is a university student.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"明日は休みだ。","translation":"Tomorrow is a day off.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0002":[{"text":"私は会社員です。","translation":"I am an office worker.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0003":[{"text":"私は大学生です。","translation":"I am a university student.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今日は仕事がありません。","translation":"As for today, I do not have work.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この本はとても面白いです。","translation":"This book is very interesting.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0004":[{"text":"私も行きます。","translation":"I will go too.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼は英語も話せます。","translation":"He can speak English too.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今日は雨も風も強いです。","translation":"Today both the rain and the wind are strong.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0005":[{"text":"これは私の傘です。","translation":"This is my umbrella.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0006":[{"text":"それは何ですか。","translation":"What is that?","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0007":[{"text":"あれは富士山です。","translation":"That over there is Mount Fuji.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0008":[{"text":"これは私の本です。","translation":"This is my book.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"兄の車は青いです。","translation":"My older brother's car is blue.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"日本の文化に興味があります。","translation":"I am interested in Japanese culture.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0009":[{"text":"この店は雰囲気がいい。","translation":"This restaurant has a nice atmosphere.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0010":[{"text":"この本は面白い。","translation":"This book is interesting.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"},{"text":"今日は昨日より暑い。","translation":"Today is hotter than yesterday.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"},{"text":"その問題は難しくない。","translation":"That problem is not difficult.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0011":[{"text":"この町は静かだ。","translation":"This town is quiet.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"},{"text":"便利なアプリを使っている。","translation":"I use a convenient app.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"},{"text":"彼はとても親切だ。","translation":"He is very kind.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0012":[{"text":"学生ですか。","translation":"Are you a student?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"明日来ますか。","translation":"Will you come tomorrow?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"何を食べますか。","translation":"What will you eat?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0013":[{"text":"猫が庭にいます。","translation":"There is a cat in the garden.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"誰が来ますか。","translation":"Who is coming?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"雨が降っています。","translation":"It is raining.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0014":[{"text":"これは本当においしいよ。","translation":"This is really delicious, you know.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"明日は休みだよ。","translation":"Tomorrow is a day off, you know.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"もうすぐ始まるよ。","translation":"It is about to start.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0015":[{"text":"今日は寒いね。","translation":"It is cold today, isn't it?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この店、おいしいね。","translation":"This restaurant is good, isn't it?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"また会おうね。","translation":"Let's meet again, okay?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0016":[{"text":"毎朝七時に起きる。","translation":"I get up at seven every morning.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"},{"text":"家で朝ご飯を食べる。","translation":"I eat breakfast at home.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"},{"text":"夜は早めに寝る。","translation":"I go to bed early at night.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0017":[{"text":"毎日日記を書く。","translation":"I write in a diary every day.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"},{"text":"週末に友達と話す。","translation":"I talk with friends on weekends.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"},{"text":"朝は水を飲む。","translation":"I drink water in the morning.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0018":[{"text":"本を読みます。","translation":"I read a book.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"水を飲みました。","translation":"I drank water.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"週末に映画を見ます。","translation":"I watch a movie on the weekend.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0019":[{"text":"毎朝六時に起きます。","translation":"I get up at six every morning.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0020":[{"text":"朝ご飯を食べない。","translation":"I do not eat breakfast.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今日はテレビを見ない。","translation":"I will not watch television today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"日曜日は早く起きない。","translation":"I do not get up early on Sundays.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0021":[{"text":"今日は日記を書かない。","translation":"I will not write in my diary today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼はあまりお酒を飲まない。","translation":"He does not drink much alcohol.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"そのことは誰にも話さない。","translation":"I will not tell anyone about that.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0022":[{"text":"パンと牛乳を買いました。","translation":"I bought bread and milk.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"机の上に本とノートがあります。","translation":"There are a book and a notebook on the desk.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"日本語と英語を勉強しています。","translation":"I study Japanese and English.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0023":[{"text":"ここで待ってください。","translation":"Please wait here.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0024":[{"text":"そこに荷物を置いてください。","translation":"Please put the luggage there.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0025":[{"text":"あそこにコンビニがあります。","translation":"There is a convenience store over there.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0026":[{"text":"図書館で勉強します。","translation":"I study at the library.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"家で晩ご飯を食べます。","translation":"I eat dinner at home.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"公園で子どもたちが遊んでいます。","translation":"Children are playing in the park.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0027":[{"text":"七時に起きます。","translation":"I get up at seven.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"学校に行きます。","translation":"I go to school.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"友達にプレゼントをあげました。","translation":"I gave a present to a friend.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0028":[{"text":"コーヒーかお茶を選んでください。","translation":"Please choose coffee or tea.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"電車かバスで行きます。","translation":"I will go by train or bus.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"土曜日か日曜日に会いましょう。","translation":"Let's meet on Saturday or Sunday.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0029":[{"text":"友達と話しました。","translation":"I talked with a friend.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"家族と旅行します。","translation":"I travel with my family.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"先生と相談しました。","translation":"I consulted with the teacher.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0030":[{"text":"明日は雨でしょう。","translation":"It will probably rain tomorrow.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0031":[{"text":"彼も来るだろう。","translation":"He will probably come too.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0032":[{"text":"机の上に本がある。","translation":"There is a book on the desk.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0033":[{"text":"公園に子どもがいる。","translation":"There are children in the park.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0034":[{"text":"この本は面白い。","translation":"This book is interesting.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0035":[{"text":"その鞄は誰のですか。","translation":"Whose bag is that?","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0036":[{"text":"あの建物は市役所です。","translation":"That building over there is city hall.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0037":[{"text":"今日はちょっと忙しいんです。","translation":"The thing is, I am a little busy today.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0038":[{"text":"昨日は暑かった。","translation":"It was hot yesterday.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"},{"text":"旅行は楽しかった。","translation":"The trip was fun.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"},{"text":"試験は思ったより難しかった。","translation":"The exam was harder than I expected.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0039":[{"text":"私は料理するのが好きです。","translation":"I like cooking.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0040":[{"text":"赤い車が止まっています。","translation":"A red car is stopped there.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今日は暑い日です。","translation":"Today is a hot day.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"面白い本を読みました。","translation":"I read an interesting book.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0041":[{"text":"静かな町に住んでいます。","translation":"I live in a quiet town.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"親切な人に助けてもらいました。","translation":"A kind person helped me.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"便利なアプリを毎日使っています。","translation":"I use a convenient app every day.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0042":[{"text":"明日、京都へ行く。","translation":"I am going to Kyoto tomorrow.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0043":[{"text":"週末に掃除をする。","translation":"I clean on the weekend.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0044":[{"text":"友達が家に来る。","translation":"A friend is coming to my house.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0045":[{"text":"昨日すしを食べた。","translation":"I ate sushi yesterday.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"昨夜その映画を見た。","translation":"I watched that movie last night.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"昨日は十一時に寝た。","translation":"I went to bed at eleven yesterday.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0046":[{"text":"昨日手紙を書いた。","translation":"I wrote a letter yesterday.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"朝コーヒーを飲んだ。","translation":"I drank coffee this morning.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"友達と長く話した。","translation":"I talked with my friend for a long time.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0047":[{"text":"私は猫が好きです。","translation":"I like cats.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0048":[{"text":"弟は納豆がきらいです。","translation":"My younger brother dislikes natto.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0049":[{"text":"私は音楽を聞くのが好きです。","translation":"I like listening to music.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0050":[{"text":"庭がある家に住みたい。","translation":"I want to live in a house with a garden.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0051":[{"text":"この問題は難しくない。","translation":"This problem is not difficult.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0052":[{"text":"電車で会社に行きます。","translation":"I go to work by train.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"箸でご飯を食べます。","translation":"I eat with chopsticks.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"日本語で説明してください。","translation":"Please explain it in Japanese.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0053":[{"text":"雨が降っているので、家にいます。","translation":"Because it is raining, I am staying home.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0054":[{"text":"眠いから、もう寝る。","translation":"I am sleepy, so I am going to bed now.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0055":[{"text":"九時から仕事です。","translation":"I work from nine o’clock.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0056":[{"text":"行きたいけど、今日は時間がない。","translation":"I want to go, but I do not have time today.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0057":[{"text":"行きたいが、今日は時間がない。","translation":"I want to go, but I do not have time today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この部屋は小さいが、便利だ。","translation":"This room is small, but convenient.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"雨だったが、予定どおり出かけた。","translation":"It was raining, but I went out as planned.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0058":[{"text":"昨日は朝ご飯を食べなかった。","translation":"I did not eat breakfast yesterday.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"昨夜はテレビを見なかった。","translation":"I did not watch television last night.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今朝は早く起きなかった。","translation":"I did not get up early this morning.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0059":[{"text":"昨日は日記を書かなかった。","translation":"I did not write in my diary yesterday.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"昨夜はお酒を飲まなかった。","translation":"I did not drink alcohol last night.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"そのことは誰にも話さなかった。","translation":"I did not tell anyone about that.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0060":[{"text":"朝起きて、顔を洗います。","translation":"I wake up and wash my face.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"駅まで歩いて、電車に乗ります。","translation":"I walk to the station and then take the train.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"ドアを開けて、部屋に入りました。","translation":"I opened the door and entered the room.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0061":[{"text":"今、本を読んでいる。","translation":"I am reading a book now.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0062":[{"text":"駅へ向かっています。","translation":"I am heading toward the station.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"来月日本へ行きます。","translation":"I will go to Japan next month.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"こちらへどうぞ。","translation":"This way, please.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0063":[{"text":"昼ご飯を食べに行く。","translation":"I am going to go eat lunch.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0064":[{"text":"あの人は誰ですか。","translation":"Who is that person?","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0065":[{"text":"なぜ日本語を勉強しているんですか。","translation":"Why are you studying Japanese?","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0066":[{"text":"どうして遅れたんですか。","translation":"Why were you late?","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0067":[{"text":"なんで笑ってるの？","translation":"Why are you laughing?","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0068":[{"text":"この本は面白いです。","translation":"This book is interesting.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今日は暑いです。","translation":"It is hot today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"その問題は難しいです。","translation":"That problem is difficult.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0069":[{"text":"この町は静かだ。","translation":"This town is quiet.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼はとても親切だ。","translation":"He is very kind.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この方法は簡単だ。","translation":"This method is simple.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0070":[{"text":"昨日は休みでした。","translation":"Yesterday was a day off.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0071":[{"text":"彼は学生じゃない。","translation":"He is not a student.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0072":[{"text":"昨日は休みじゃなかった。","translation":"Yesterday was not a day off.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0073":[{"text":"昨日はあまり寒くなかった。","translation":"It was not very cold yesterday.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0074":[{"text":"彼は「行く」と言いました。","translation":"He said, “I will go.”","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"明日は雨が降ると思います。","translation":"I think it will rain tomorrow.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"先生は静かにするようにと言った。","translation":"The teacher said to be quiet.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0075":[{"text":"田中さん、明日は休むって。","translation":"I heard Tanaka is taking tomorrow off.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0077":[{"text":"昨日買った本を読みました。","translation":"I read the book that I bought yesterday.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼が作った料理はおいしかった。","translation":"The food that he made was delicious.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"駅で会った人は高校の同級生だった。","translation":"The person I met at the station was a high-school classmate.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0078":[{"text":"赤いのをください。","translation":"Please give me the red one.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"私のは机の上です。","translation":"Mine is on the desk.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"大きいのと小さいの、どちらがいいですか。","translation":"Which is better, the big one or the small one?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0079":[{"text":"ここで写真を撮るな。","translation":"Do not take pictures here.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"そんなことを言うな。","translation":"Don't say things like that.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"危ないから触るな。","translation":"Don't touch it because it is dangerous.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0080":[{"text":"水だけ飲んだ。","translation":"I only drank water.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0081":[{"text":"どれがあなたの傘ですか。","translation":"Which one is your umbrella?","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0082":[{"text":"駅はどこですか。","translation":"Where is the station?","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0083":[{"text":"どの電車に乗ればいいですか。","translation":"Which train should I take?","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0084":[{"text":"窓が開いている。","translation":"The window is open.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0085":[{"text":"宿題をしてからゲームをする。","translation":"I play games after doing my homework.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0086":[{"text":"家に帰って、すぐ寝ました。","translation":"I went home and then went straight to sleep.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"シャワーを浴びて、朝ご飯を食べました。","translation":"I took a shower and then ate breakfast.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"財布を取って、店を出ました。","translation":"I picked up my wallet and left the store.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0087":[{"text":"もう昼ご飯を食べた。","translation":"I already ate lunch.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0088":[{"text":"まだ雨が降っている。","translation":"It is still raining.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0089":[{"text":"まだ宿題をしていません。","translation":"I still have not done my homework.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼はまだ来ていません。","translation":"He has not come yet.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"その映画はまだ見ていません。","translation":"I have not seen that movie yet.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0090":[{"text":"少し遅れてもいいです。","translation":"It is okay if you are a little late.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0091":[{"text":"日本に行きたい。","translation":"I want to go to Japan.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0092":[{"text":"週末は映画を見たり、本を読んだりする。","translation":"On weekends I do things like watch movies and read books.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0093":[{"text":"この仕事はけっこう時間がかかる。","translation":"This job takes quite a lot of time.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0094":[{"text":"昨日はたくさん歩いた。","translation":"I walked a lot yesterday.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0095":[{"text":"寝る前に歯を磨く。","translation":"I brush my teeth before going to bed.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0096":[{"text":"駅まで十分くらいかかる。","translation":"It takes about ten minutes to get to the station.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0097":[{"text":"仕事は五時までです。","translation":"Work is until five o’clock.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0098":[{"text":"雨がやむまでここで待とう。","translation":"Let’s wait here until the rain stops.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0099":[{"text":"昨日は食べすぎた。","translation":"I ate too much yesterday.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0100":[{"text":"飲み物はコーヒーにします。","translation":"I will choose coffee for my drink.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0101":[{"text":"春になると暖かくなります。","translation":"When spring comes, it gets warmer.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"練習して日本語が上手になった。","translation":"I practiced and became better at Japanese.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"夜になると町は静かになる。","translation":"At night, the town becomes quiet.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0102":[{"text":"果物のなかでりんごがいちばん好きです。","translation":"Of all fruits, I like apples the most.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"クラスのなかで田中さんがいちばん背が高いです。","translation":"Tanaka is the tallest in the class.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"四季のなかで春がいちばん好きです。","translation":"Of the four seasons, I like spring the most.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0103":[{"text":"電車よりバスのほうが安いです。","translation":"The bus is cheaper than the train.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"犬より猫のほうが好きです。","translation":"I like cats more than dogs.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"去年より今年のほうが忙しいです。","translation":"This year is busier than last year.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0104":[{"text":"何か食べたいです。","translation":"I want to eat something.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"冷蔵庫には何もありません。","translation":"There is nothing in the refrigerator.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"何か質問がありますか。","translation":"Do you have any questions?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0105":[{"text":"誰かがドアをたたいた。","translation":"Someone knocked on the door.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"},{"text":"どこかで少し休もう。","translation":"Let’s rest somewhere for a little while.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"},{"text":"今日は誰も来なかった。","translation":"No one came today.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0106":[{"text":"一緒に帰りましょう。","translation":"Let’s go home together.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0107":[{"text":"この冷凍アスパラガスは何分ゆでましょうか。","translation":"How many minutes shall I boil this frozen asparagus?","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"219179","matchedSignature":"ましょうか","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"んじゃ、ほんのり・・・実力を出しましょうかね。","translation":"Well then, let's show a little of our real strength shall we?","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"76359","matchedSignature":"ましょうか","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"歩きましょうか、それともバスで行きますか。","translation":"Shall we walk or take the bus?","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"83209","matchedSignature":"ましょうか","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0108":[{"text":"今度、一緒に映画を見ませんか。","translation":"Would you like to watch a movie together sometime?","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0109":[{"text":"ここに座ってもいいですか。","translation":"May I sit here?","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0110":[{"text":"録音が終わったらそれを再生して聞かせてください。","translation":"Please play it back for me after you've finished the recording.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"77231","matchedSignature":"てください","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"疑問があれば、このガイドブックを参照してください。","translation":"If you have some questions, please refer to this guidebook.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"149531","matchedSignature":"てください","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"シートを自分に合うように調整してください。","translation":"Please adjust the seat to fit you.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"216591","matchedSignature":"てください","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0111":[{"text":"まあまあ、そう怒らないでくださいな。","translation":"Now, please don't get so angry.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"76417","matchedSignature":"ないでください","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"卵をあまり固くゆでないでください。","translation":"Please don't boil the eggs so hard.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"78483","matchedSignature":"ないでください","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"細かい意訳誤訳は気にしないでください。","translation":"Please don't worry about the finer details of free vs mis-translation.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"74226","matchedSignature":"ないでください","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0112":[{"text":"ここで写真を撮ってはいけない。","translation":"You must not take pictures here.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0113":[{"text":"君は標準英語を学ばなくてはいけない。","translation":"You have to learn standard English.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"176910","matchedSignature":"なくてはいけない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"僕は英語の試験の準備をしなくてはいけない。","translation":"I have to prepare for the English test.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"81993","matchedSignature":"なくてはいけない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"いったん約束をしたら、守らなくてはいけない。","translation":"Once you have made a promise, you should keep it.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"228864","matchedSignature":"なくてはいけない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0114":[{"text":"我々は地方の慣習を尊重しなくてはならない。","translation":"We have to respect local customs.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"185683","matchedSignature":"なくてはならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"出来るだけ争いを避けなくてはならない。","translation":"We have to avoid a conflict as far as possible.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"147676","matchedSignature":"なくてはならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"ただし、列をつくって並ばなくてはならないが・・・。","translation":"However, you have to queue...","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"203649","matchedSignature":"なくてはならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0115":[{"text":"彼がやることをしっかり警戒したほうがいいですよ。","translation":"Now it would be better to keep a sharp lookout for what he might do.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"120695","matchedSignature":"たほうがいい","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"たまには酒にでも酔ってはじけて日頃の鬱憤晴らしたほうがいいんじゃないか。","translation":"Isn't it better to get drunk and cut loose once in a while and blow off the tension of daily frustration?","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"76572","matchedSignature":"たほうがいい","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"眠る前に電気を消したほうがいいですよ。","translation":"You had better turn off the light before you go to sleep.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"80975","matchedSignature":"たほうがいい","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0116":[{"text":"事故のことはお父さんに言わないほうがいいよ。","translation":"You had better not tell your father about the accident.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"150858","matchedSignature":"ないほうがいい","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"私は彼に手を貸してやらないほうがいいと思う。","translation":"I think it's better not to lend him a hand.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"154121","matchedSignature":"ないほうがいい","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"冬にはそんな高い山に登らないほうがいいよ。","translation":"You had better not climb such high mountains in winter.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"124376","matchedSignature":"ないほうがいい","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0117":[{"text":"もう行かなくちゃ。","translation":"I have to go now.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0118":[{"text":"机の上に本やノートがあります。","translation":"There are things like books and notebooks on the desk.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"週末は映画や音楽を楽しみます。","translation":"On weekends I enjoy things like movies and music.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"スーパーで野菜や果物を買いました。","translation":"I bought vegetables, fruit, and the like at the supermarket.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0119":[{"text":"カミナリが光ったその後【くわばらくわばら】と唱えたもしくは、唱える人を見たことがあるだろう。","translation":"I expect you've chanted \"kuwabara kuwabara\" after a lightning flash, or have seen somebody do so.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"74100","matchedSignature":"たことがある","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0120":[{"text":"毎朝この道を歩いている。","translation":"I walk this road every morning.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0121":[{"text":"この部屋は広くて明るいです。","translation":"This room is spacious and bright.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼は親切で真面目です。","translation":"He is kind and serious.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼女は学生で、弟は高校生です。","translation":"She is a student, and her younger brother is a high-school student.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0122":[{"text":"この店は安くておいしいです。","translation":"This restaurant is inexpensive and delicious.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"その部屋は狭くて暗いです。","translation":"That room is narrow and dark.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"このかばんは軽くて丈夫です。","translation":"This bag is light and durable.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0123":[{"text":"私は絵を描くのがへたです。","translation":"I am bad at drawing.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0124":[{"text":"あなたは絵を書くのがじょうずですね。","translation":"You are a good painter, aren't you?","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"232165","matchedSignature":"のがじょうず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、あなたは絵を書くのがじょうずですね。","translation":"In fact, you are a good painter, aren't you?","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"のがじょうず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「あなたは絵を書くのがじょうずですね」と言った。","translation":"A friend said, “You are a good painter, aren't you.”","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"のがじょうず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0125":[{"text":"赤いのをください。","translation":"Please give me the red one.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0126":[{"text":"妹に誕生日プレゼントをあげた。","translation":"I gave my younger sister a birthday present.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0127":[{"text":"友達が駅まで送ってくれた。","translation":"My friend gave me a ride to the station.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0128":[{"text":"先生に本をもらった。","translation":"I received a book from my teacher.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0129":[{"text":"この店は高いけれども、料理はおいしい。","translation":"This restaurant is expensive, but the food is good.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0130":[{"text":"来年、日本へ留学するつもりだ。","translation":"I intend to study abroad in Japan next year.","source":"AIDA manually audited N5 grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0131":[],"jp-g-0132":[],"jp-g-0133":[],"jp-g-0134":[],"jp-g-0135":[],"jp-g-0136":[],"jp-g-0137":[{"text":"僕らは子どものころから友達だ。","translation":"We have been friends since childhood.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼らは先に帰りました。","translation":"They went home first.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"学生らが入口に集まった。","translation":"The students gathered at the entrance.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0138":[],"jp-g-0139":[],"jp-g-0140":[],"jp-g-0141":[],"jp-g-0142":[],"jp-g-0143":[],"jp-g-0144":[],"jp-g-0145":[],"jp-g-0146":[{"text":"先生に褒められました。","translation":"I was praised by the teacher.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"子どものころ犬に噛まれた。","translation":"I was bitten by a dog when I was a child.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"友達に写真を撮られた。","translation":"A friend took a picture of me.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0147":[{"text":"私がドアを開けると、ドアがゆっくり開いた。","translation":"When I opened the door, the door opened slowly.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"電気をつけると、すぐに電気がついた。","translation":"When I turned on the light, it came on immediately.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"財布を落としたので、財布が道に落ちていた。","translation":"I dropped my wallet, so it was lying on the road.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0148":[],"jp-g-0149":[],"jp-g-0150":[],"jp-g-0151":[],"jp-g-0152":[],"jp-g-0153":[],"jp-g-0154":[],"jp-g-0155":[],"jp-g-0156":[{"text":"本を読み終わった。","translation":"I finished reading the book.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"ご飯を食べ終わったら出かけます。","translation":"I will go out after I finish eating.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"仕事が終わるまで待ってください。","translation":"Please wait until the work is finished.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0157":[],"jp-g-0158":[],"jp-g-0159":[],"jp-g-0160":[{"text":"一日に三回薬を飲みます。","translation":"I take medicine three times a day.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"週に二回ジムへ行きます。","translation":"I go to the gym twice a week.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"一年に一度家族で旅行します。","translation":"My family travels once a year.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0161":[],"jp-g-0162":[],"jp-g-0163":[],"jp-g-0164":[],"jp-g-0165":[],"jp-g-0166":[],"jp-g-0167":[],"jp-g-0168":[],"jp-g-0169":[],"jp-g-0170":[],"jp-g-0171":[],"jp-g-0172":[{"text":"この部屋の広さに驚きました。","translation":"I was surprised by the size of this room.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"山の高さを測ります。","translation":"We measure the height of the mountain.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼の優しさがうれしかった。","translation":"I was happy about his kindness.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0173":[],"jp-g-0174":[],"jp-g-0175":[],"jp-g-0176":[],"jp-g-0177":[],"jp-g-0178":[],"jp-g-0179":[{"text":"私はあまりテレビを見ません。","translation":"I do not watch much television.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この料理はあまり辛くないです。","translation":"This dish is not very spicy.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"最近あまり眠れていません。","translation":"Recently I have not been sleeping very well.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0180":[{"text":"時間があれば行きます。","translation":"If I have time, I will go.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"安ければ買います。","translation":"If it is inexpensive, I will buy it.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"分からなければ聞いてください。","translation":"If you do not understand, please ask.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0181":[],"jp-g-0182":[],"jp-g-0183":[],"jp-g-0184":[],"jp-g-0185":[],"jp-g-0186":[],"jp-g-0187":[],"jp-g-0188":[],"jp-g-0189":[{"text":"来年日本へ行こうと思っています。","translation":"I am thinking of going to Japan next year.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今日は早く寝ようと思う。","translation":"I think I will go to bed early today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この問題について先生に聞こうと思います。","translation":"I think I will ask the teacher about this problem.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0190":[{"text":"もっと早く歩いてください。","translation":"Please walk faster.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"静かに話してください。","translation":"Please speak quietly.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"名前をきれいに書いてください。","translation":"Please write your name neatly.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0191":[{"text":"部屋を静かにしてください。","translation":"Please make the room quiet.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"髪を短くしました。","translation":"I made my hair shorter.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"コーヒーを少し甘くした。","translation":"I made the coffee a little sweeter.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0192":[],"jp-g-0193":[{"text":"いつかは君も貯蓄の重要さを悟るようになるだろう。","translation":"Some day you will come to realize the importance of saving.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"229006","matchedSignature":"ようになる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"動けるようになると健康の有難さを実感しますよね。","translation":"It's when you become able to move that the real value of health hits home.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"75221","matchedSignature":"ようになる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"個々の木を見分けるのが困難になってはじめて森が見えるようになるのである。","translation":"You get to see the wood only when it becomes too difficult to distinguish individual trees.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"174658","matchedSignature":"ようになる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0194":[{"text":"彼は毎日のようにジムに行きます。","translation":"He goes to the gym almost every day.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"最近は毎週のように雨が降ります。","translation":"Recently it rains almost every week.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼女は毎晩のように電話してきます。","translation":"She calls almost every night.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0195":[],"jp-g-0196":[],"jp-g-0197":[],"jp-g-0198":[],"jp-g-0199":[],"jp-g-0200":[],"jp-g-0201":[{"text":"曇天の日は晴天のときより音がよく聞こえるのです。","translation":"On cloudy days, you can hear distant sounds better than in clear weather.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"75833","matchedSignature":"聞こえる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"猫が窓を引っかいているのが聞こえる。","translation":"I can hear a cat scratching at the window.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"121992","matchedSignature":"聞こえる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"悪魔の話をすると彼の骨がカタカタいう音が聞こえる。","translation":"When you talk of the devil you will hear his bones rattle.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"191369","matchedSignature":"聞こえる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0202":[],"jp-g-0203":[],"jp-g-0204":[],"jp-g-0205":[{"text":"三時間も待ちました。","translation":"I waited as long as three hours.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"会場には百人も来ました。","translation":"As many as one hundred people came to the venue.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"財布には一円もありません。","translation":"There is not even one yen in my wallet.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0206":[],"jp-g-0207":[],"jp-g-0208":[],"jp-g-0209":[{"text":"人の出会いなんて、なんだかんだで、最初のインパクトで５０％以上は決まってしまっている。","translation":"When people meet, first impressions determine more than 50 percent of whatever happens next.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"144598","matchedSignature":"以上","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"その山は海抜3,000メートル以上にある。","translation":"The mountain is more than 3,000 meters above sea level.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"210448","matchedSignature":"以上","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"世界の人口は産業革命以来、３倍以上になった。","translation":"Since the Industrial Revolution, the world population has more than tripled.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"143428","matchedSignature":"以上","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0210":[],"jp-g-0211":[],"jp-g-0212":[],"jp-g-0213":[],"jp-g-0214":[],"jp-g-0215":[],"jp-g-0216":[{"text":"完成まで三日はかかります。","translation":"It will take at least three days to finish.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"その修理には一万円は必要です。","translation":"That repair will require at least ten thousand yen.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"あと二時間は待つことになる。","translation":"We will have to wait at least another two hours.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0217":[],"jp-g-0218":[],"jp-g-0219":[{"text":"財布に千円しかありません。","translation":"I have only one thousand yen in my wallet.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"あと三分しかない。","translation":"There are only three minutes left.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"会場には十人しかいませんでした。","translation":"There were only ten people at the venue.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0220":[{"text":"富士山は日本の有名な山の一つです。","translation":"Mount Fuji is one of Japan's famous mountains.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"京都は人気の観光地の一つです。","translation":"Kyoto is one of the popular tourist destinations.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"睡眠は健康を支える要素の一つです。","translation":"Sleep is one of the factors that support health.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0221":[],"jp-g-0222":[{"text":"少しも疲れていません。","translation":"I am not tired in the least.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼の説明は少しも分かりませんでした。","translation":"I did not understand his explanation at all.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"私は少しも後悔していません。","translation":"I do not regret it at all.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0223":[{"text":"この町には外国人も少なくない。","translation":"There are quite a few foreigners in this town.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"その意見に賛成する人は少なくない。","translation":"Quite a few people agree with that opinion.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"毎日運動する学生も少なくない。","translation":"Not a few students exercise every day.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0224":[{"text":"雨の場合は試合を中止します。","translation":"In the event of rain, the game will be canceled.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"遅れる場合は連絡してください。","translation":"If you are going to be late, please contact me.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"問題がある場合は受付に相談してください。","translation":"If there is a problem, please consult the reception desk.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0225":[{"text":"ちょっと待って。","translation":"Wait a moment.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"これ見て。","translation":"Look at this.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"少し手伝って。","translation":"Help me a little.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0226":[{"text":"彼女は私の手を握り締めて会えてよかったといった。","translation":"She clasped my hands and said she was glad to see me.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"89366","matchedSignature":"てよかった","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0227":[{"text":"母は子どもに野菜を食べさせた。","translation":"The mother made the child eat vegetables.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"先生は学生に作文を書かせました。","translation":"The teacher had the students write compositions.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"私は弟を先に帰らせた。","translation":"I let my younger brother go home first.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0228":[],"jp-g-0229":[],"jp-g-0230":[{"text":"大事な約束を忘れてしまった。","translation":"I unfortunately forgot an important promise.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"ケーキを全部食べちゃった。","translation":"I ended up eating the whole cake.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"スマホを落として壊してしまった。","translation":"I dropped my phone and ended up breaking it.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0231":[{"text":"電車が遅れて、学校に遅刻しました。","translation":"The train was delayed, so I was late for school.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"風邪をひいて、仕事を休みました。","translation":"I caught a cold, so I took the day off work.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"財布をなくして、困っています。","translation":"I lost my wallet, so I am in trouble.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0232":[],"jp-g-0233":[{"text":"歩いて駅まで行きます。","translation":"I go to the station on foot.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"自転車で学校へ行きます。","translation":"I go to school by bicycle.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"笑顔で答えました。","translation":"I answered with a smile.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0234":[],"jp-g-0235":[{"text":"みんなに分かるように説明してほしいです。","translation":"I want you to explain it so everyone can understand.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"遅れないように早く来てほしい。","translation":"I want you to come early so you will not be late.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"子どもが安心できるようにそばにいてほしい。","translation":"I want you to stay nearby so the child can feel safe.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0236":[{"text":"寝ている間に雨が降った。","translation":"It rained while I was sleeping.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"母が買い物している間に夕食を作った。","translation":"I made dinner while my mother was shopping.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"日本にいる間に京都へ行きたい。","translation":"I want to visit Kyoto while I am in Japan.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0237":[{"text":"慌てて着替えなくてもいいよ。急いでいるわけじゃないから。","translation":"You don't have to dress in a mad rush; we've got time.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"173599","matchedSignature":"なくてもいい","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0238":[],"jp-g-0239":[{"text":"足手まといになる子供をお頼みしてすみません。","translation":"I am sorry to encumber you with the children.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"139838","matchedSignature":"てすみません","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"長い間、お待たせしてすみませんでした。","translation":"I'm sorry I have kept you waiting so long.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"125967","matchedSignature":"てすみません","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"長くお待たせしてすみませんでした。","translation":"I am sorry to have kept you waiting so long.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"125913","matchedSignature":"てすみません","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0240":[],"jp-g-0241":[],"jp-g-0242":[],"jp-g-0243":[],"jp-g-0244":[{"text":"兄は東京に住んでいて、姉は大阪に住んでいます。","translation":"My older brother lives in Tokyo, while my older sister lives in Osaka.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"父は会社で働いていて、母は家で仕事をしています。","translation":"My father works at a company, while my mother works from home.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"窓が開いていて、冷たい風が入ってきます。","translation":"The window is open, and cold air is coming in.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0245":[],"jp-g-0246":[{"text":"状況を改善するのを手伝ってくれてありがとう。","translation":"Thank you for helping me correct the situation.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"146013","matchedSignature":"てくれてありがとう","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"親切にしてくれてありがとう。","translation":"Thank you for your kindness.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"144789","matchedSignature":"てくれてありがとう","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0247":[],"jp-g-0248":[{"text":"諺を英語にする行為に意味があるのだろうか。","translation":"I wonder if there is any meaning to putting proverbs into English.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"174661","matchedSignature":"のだろうか","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼女はどこで英会話を勉強したのだろうか。","translation":"I wonder where she studied English conversation.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"91990","matchedSignature":"のだろうか","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼女は結婚しているのだろうか。","translation":"I wonder if she is married.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"90289","matchedSignature":"のだろうか","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0249":[{"text":"先生はもうお帰りになりました。","translation":"The teacher has already gone home.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"社長はこの資料をお読みになります。","translation":"The company president will read this document.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"こちらで少しお待ちになりますか。","translation":"Would you wait here for a moment?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0250":[],"jp-g-0251":[{"text":"どうぞお入りください。","translation":"Please come in.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"こちらにお名前をお書きください。","translation":"Please write your name here.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"こちらでしばらくお待ちください。","translation":"Please wait here for a while.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0252":[],"jp-g-0253":[],"jp-g-0254":[],"jp-g-0255":[{"text":"お荷物をお持ちします。","translation":"I will carry your luggage.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"後ほどこちらからお電話します。","translation":"I will call you later.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"私がお手伝いします。","translation":"I will help you.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0256":[],"jp-g-0257":[{"text":"明瞭な陳述をしていただけませんか。","translation":"Will you please make a specific statement?","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"80234","matchedSignature":"ていただけませんか","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"明確な陳述をしていただけませんか。","translation":"Will you please make a specific statement?","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"80703","matchedSignature":"ていただけませんか","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0258":[],"jp-g-0259":[],"jp-g-0260":[{"text":"海外旅行にはパスポートが必要です。","translation":"A passport is necessary for overseas travel.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この仕事には経験が必要だ。","translation":"Experience is necessary for this job.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"上達するには毎日の練習が必要です。","translation":"Daily practice is necessary to improve.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0261":[],"jp-g-0262":[{"text":"もう一度確認する必要があります。","translation":"It is necessary to check once more.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"早めに予約する必要がある。","translation":"It is necessary to make a reservation early.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この問題について話し合う必要があります。","translation":"We need to discuss this problem.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0263":[],"jp-g-0264":[{"text":"私は納豆を食べられます。","translation":"I can eat natto.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この漢字は読めますか。","translation":"Can you read this kanji?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"明日は早く帰れます。","translation":"I can go home early tomorrow.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0265":[],"jp-g-0266":[],"jp-g-0267":[],"jp-g-0268":[{"text":"春になると暖かくなる。","translation":"When spring comes, it gets warmer.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"このボタンを押すとドアが開きます。","translation":"When you press this button, the door opens.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"夜になるとこの道は暗くなる。","translation":"When night comes, this road gets dark.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0269":[],"jp-g-0270":[{"text":"彼女が彼の申し込みを拒絶したはずがない。","translation":"She cannot have turned down his offer.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"95249","matchedSignature":"はずがない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"ポットにもうお茶が残っているはずがない。","translation":"There cannot be any tea left in the pot.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"196230","matchedSignature":"はずがない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼女は学校の成績が良かったはずがない。","translation":"She cannot have done well at school.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"90707","matchedSignature":"はずがない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0271":[{"text":"冷蔵庫には水しかありません。","translation":"There is only water in the refrigerator.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今は待つしかない。","translation":"For now, there is nothing to do but wait.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今日は一時間しか勉強できません。","translation":"Today I can study for only one hour.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0272":[],"jp-g-0273":[{"text":"彼女は情勢を把握することができる。","translation":"She is able to grasp the situation.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"88627","matchedSignature":"ことができる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"ヘリコプターは垂直に離陸し、着陸することができる。","translation":"A helicopter is able to take off and land straight up and down.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"196712","matchedSignature":"ことができる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼女は今日それをし終えることができるだろうか。","translation":"Will she be able to finish it today?","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"89991","matchedSignature":"ことができる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0274":[],"jp-g-0275":[],"jp-g-0276":[{"text":"安いし、おいしいし、この店が好きです。","translation":"It is inexpensive and delicious, so I like this restaurant.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"駅に近いし、部屋も広いです。","translation":"It is close to the station, and the room is spacious too.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"時間もないし、今日はやめましょう。","translation":"We do not have time either, so let's stop for today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0277":[{"text":"この机は木でできています。","translation":"This desk is made of wood.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"日本酒は米からできます。","translation":"Sake is made from rice.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この箱は紙でできています。","translation":"This box is made of paper.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0278":[],"jp-g-0279":[],"jp-g-0280":[],"jp-g-0281":[{"text":"コーヒーとお茶と、どちらが好きですか。","translation":"Which do you like better, coffee or tea?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"電車とバスと、どちらが速いですか。","translation":"Which is faster, the train or the bus?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"夏と冬と、どちらが好きですか。","translation":"Which do you like better, summer or winter?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0282":[],"jp-g-0283":[{"text":"僕は英語の試験の準備をしなければいけない。","translation":"I have to prepare for the English test.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"81991","matchedSignature":"なければいけない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0284":[{"text":"明日までにその仕事を仕上げなければならない。","translation":"I have to go through the task by tomorrow.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"80382","matchedSignature":"なければならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"芸術家は色彩に対する目を持っていなければならない。","translation":"An artist must have an eye for color.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"176025","matchedSignature":"なければならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"今頃の時期はなだれに注意しなければならない。","translation":"You have to watch out for avalanches at this time of the year.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"172414","matchedSignature":"なければならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0285":[],"jp-g-0286":[{"text":"先生は私に早く来るように言いました。","translation":"The teacher told me to come early.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"母は弟に忘れ物をしないように言った。","translation":"My mother told my younger brother not to forget anything.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"医者は父にもっと休むように言いました。","translation":"The doctor told my father to rest more.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0287":[{"text":"来週東京へ出張する予定です。","translation":"I plan to go to Tokyo on business next week.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"夏休みに北海道へ行く予定だ。","translation":"I plan to go to Hokkaido during summer vacation.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"会議は三時に終わる予定です。","translation":"The meeting is scheduled to end at three.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0288":[{"text":"試験に合格するように祈っています。","translation":"I am praying that I pass the exam.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"明日晴れるように祈った。","translation":"I prayed that it would be sunny tomorrow.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"みんなが無事に帰れるように祈ります。","translation":"I pray that everyone can return safely.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0289":[],"jp-g-0290":[],"jp-g-0291":[{"text":"早く来い！","translation":"Come quickly!","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"静かにしろ！","translation":"Be quiet!","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"よく見ろ！","translation":"Look carefully!","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0292":[],"jp-g-0293":[],"jp-g-0294":[],"jp-g-0295":[],"jp-g-0296":[],"jp-g-0297":[],"jp-g-0298":[],"jp-g-0299":[{"text":"計算の間違いに気がついた。","translation":"I noticed the calculation error.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"駅を通り過ぎたことに気がついた。","translation":"I realized that I had passed the station.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼の声を聞いて、すぐ本人だと気がついた。","translation":"I heard his voice and immediately realized it was him.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0300":[{"text":"コーヒーでもお茶でも、好きなほうをどうぞ。","translation":"Coffee or tea—please have whichever you prefer.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"電車でもバスでも行けます。","translation":"You can go either by train or by bus.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今日でも明日でも大丈夫です。","translation":"Either today or tomorrow is fine.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0301":[],"jp-g-0302":[],"jp-g-0303":[{"text":"彼がいつ来るか分かりません。","translation":"I do not know when he will come.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"どこで買えるか教えてください。","translation":"Please tell me where I can buy it.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"何を食べるかまだ決めていません。","translation":"I have not decided what to eat yet.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0304":[],"jp-g-0305":[],"jp-g-0306":[{"text":"この変化は気候の影響だと考えられています。","translation":"This change is considered to be an effect of the climate.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"その遺跡は千年以上前のものだと考えられている。","translation":"The ruins are thought to be more than a thousand years old.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"睡眠不足が原因だと考えられています。","translation":"Lack of sleep is thought to be the cause.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0307":[{"text":"その発明はエジソンがしたものとされている。","translation":"The invention is accredited to Edison.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"207183","matchedSignature":"とされている","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"電灯の発明はエジソンによるとされている。","translation":"The invention of electric light is accredited to Edison.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"124765","matchedSignature":"とされている","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0308":[{"text":"彼は当時町で最も金持ちだったといわれている。","translation":"He is said to have been the richest man in town at that time.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"101740","matchedSignature":"といわれている","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"女性は職場や地域社会でますます重要な責任を担うようになっているので、育児と仕事の両方からストレスを感じている人の数が増えているといわれている。","translation":"Since women are taking on more responsibilities at work and in the community, it is said that the number of women with stress from both child-rearing and work is increasing.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"147248","matchedSignature":"といわれている","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0309":[{"text":"こんな恥をかくのならいっそ生まれなければよかった。","translation":"I had rather never have been born than have seen this day of shame.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"76708","matchedSignature":"ばよかった","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"無茶しなければよかった。","translation":"I shouldn't have overdone it.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"80898","matchedSignature":"ばよかった","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼女の警告にきちんと耳を傾ければよかったのに。","translation":"You should have paid attention to her warning.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"94497","matchedSignature":"ばよかった","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0310":[],"jp-g-0311":[],"jp-g-0312":[],"jp-g-0313":[],"jp-g-0314":[],"jp-g-0315":[],"jp-g-0316":[],"jp-g-0317":[],"jp-g-0318":[],"jp-g-0319":[],"jp-g-0320":[],"jp-g-0321":[{"text":"バスがなかなか来ません。","translation":"The bus is taking a long time to come.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この漢字はなかなか覚えられません。","translation":"I cannot easily memorize this kanji.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"忙しくてなかなか休めません。","translation":"I am busy and cannot readily take a break.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0322":[],"jp-g-0323":[],"jp-g-0324":[{"text":"その話はまったく知りません。","translation":"I do not know about that at all.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今日はまったく時間がありません。","translation":"I have no time at all today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼の説明はまったく分かりませんでした。","translation":"I did not understand his explanation at all.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0325":[],"jp-g-0326":[],"jp-g-0327":[],"jp-g-0328":[],"jp-g-0329":[],"jp-g-0330":[],"jp-g-0331":[],"jp-g-0332":[{"text":"友達との旅行は楽しかったです。","translation":"The trip with my friend was fun.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"日本への留学を考えています。","translation":"I am considering studying abroad in Japan.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"先生からのメールを読みました。","translation":"I read the email from my teacher.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0333":[],"jp-g-0334":[],"jp-g-0335":[],"jp-g-0336":[],"jp-g-0337":[{"text":"練習すればするほど上手になります。","translation":"The more you practice, the better you become.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"読めば読むほど面白くなります。","translation":"The more you read it, the more interesting it becomes.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"考えれば考えるほど分からなくなります。","translation":"The more I think about it, the less I understand.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0338":[{"text":"東京は大阪ほど暑くないです。","translation":"Tokyo is not as hot as Osaka.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この問題は前の問題ほど難しくありません。","translation":"This problem is not as difficult as the previous one.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"私は兄ほど背が高くありません。","translation":"I am not as tall as my older brother.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0339":[],"jp-g-0340":[],"jp-g-0341":[],"jp-g-0342":[],"jp-g-0343":[],"jp-g-0344":[{"text":"狐は他のどんな動物よりもずるいということだ。","translation":"It is said that the fox is more cunning than any other animal.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"174467","matchedSignature":"ということだ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"死傷者は合計1000名となったということだ。","translation":"Casualties are said to total up to 1,000.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"168127","matchedSignature":"ということだ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0345":[{"text":"友達は「地球が丸いというのは事実だ」と言った。","translation":"A friend said, “It is a fact that the earth is round.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"というのは","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0346":[],"jp-g-0347":[],"jp-g-0348":[],"jp-g-0349":[{"text":"彼らは話をしている最中に電話を切られた。","translation":"They were cut off in the middle of their telephone conversation.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"96009","matchedSignature":"最中に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼は会話の最中に口を挟むことがよくある。","translation":"He often breaks into the middle of a conversation.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"109043","matchedSignature":"最中に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"会議の最中に電話が鳴った。","translation":"The phone rang in the middle of the meeting.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"最中に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0350":[],"jp-g-0351":[],"jp-g-0352":[],"jp-g-0353":[],"jp-g-0354":[],"jp-g-0355":[],"jp-g-0356":[],"jp-g-0357":[],"jp-g-0358":[],"jp-g-0359":[],"jp-g-0360":[{"text":"彼女はときに空想と現実を混同することがある。","translation":"She sometimes mixes up fancies with realities.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"91999","matchedSignature":"ことがある","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"工場の廃棄物が私達の川を汚すことがある。","translation":"Factory waste sometimes pollutes our rivers.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"173730","matchedSignature":"ことがある","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"貧困のために人々は時に犯罪を犯すことがある。","translation":"Poverty sometimes drives people to commit crimes.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"85174","matchedSignature":"ことがある","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0361":[{"text":"ここで迷わず迂回路を取ることにする。","translation":"Here I decide, without hesitating, to take the alternative route.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"74578","matchedSignature":"ことにする","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0362":[],"jp-g-0363":[{"text":"明日雨が降れば、丸１週間雨が続くことになる。","translation":"It will have been raining a whole week if it is rainy tomorrow.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"80344","matchedSignature":"ことになる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"明日で５日間雪が降り続くことになる。","translation":"It will have been snowing for five days tomorrow.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"80593","matchedSignature":"ことになる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼らはおそらく結果として多くの心理的問題を抱えることになり、それは長い目で見ればもっと悪いことになるだろう。","translation":"They will probably have many psychological problems as a result, and that would be worse in the long run.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"98164","matchedSignature":"ことになる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0364":[{"text":"アイルランドは刺繍で有名である。","translation":"Ireland is famous for lace.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"234547","matchedSignature":"で有名","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"私たちは梅の花で有名な水戸公園を見に行った。","translation":"We visited Mito Park, which is famous for its plum blossoms.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"165351","matchedSignature":"で有名","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼は議会で延々と長広舌を振るうことで有名だ。","translation":"He was famous for his marathon speeches in parliament.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"108524","matchedSignature":"で有名","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0365":[{"text":"暗殺が世界の歴史を変えたことはない。","translation":"Assassination has never changed the history of the world.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"191249","matchedSignature":"ことはない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"キリスト教の信者だったことはない。","translation":"I was never a believer of Christianity.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"225758","matchedSignature":"ことはない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"改めるのに遅すぎるということはない。","translation":"It is never too late to mend.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"185143","matchedSignature":"ことはない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0366":[],"jp-g-0367":[],"jp-g-0368":[],"jp-g-0369":[{"text":"この机は子供たちに合わせて高さが調節できる。","translation":"You can adjust this desk to the height of any child.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"222525","matchedSignature":"に合わせて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0370":[],"jp-g-0371":[{"text":"働く父の姿を見て育った。","translation":"I grew up watching my father work.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"制服を着た彼女の姿が見えた。","translation":"I could see her figure in a uniform.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"成長した子どもの姿に感動した。","translation":"I was moved by the sight of the grown child.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0372":[],"jp-g-0373":[],"jp-g-0374":[],"jp-g-0375":[{"text":"多くの道路が冠水し、その結果大幅な遅れが出ている。","translation":"Many roads are flooded. As a result there are long delays.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"138309","matchedSignature":"その結果","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼女はその結果を自分の不注意に結び付けた。","translation":"She related the result to her carelessness.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"92514","matchedSignature":"その結果","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"その結果、５月下旬に不安神経症や不眠症と診断された。","translation":"As a result, he was diagnosed with insomnia and anxiety neurosis near the end of May.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"76625","matchedSignature":"その結果","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0376":[],"jp-g-0377":[{"text":"どんなに忙しくても朝ご飯を食べます。","translation":"No matter how busy I am, I eat breakfast.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"どんなに考えても答えが出ません。","translation":"No matter how much I think, I cannot find an answer.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"どんなに遠くても会いに行きます。","translation":"No matter how far away it is, I will go to see you.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0378":[{"text":"いくら食べても太りません。","translation":"No matter how much I eat, I do not gain weight.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"いくら説明しても分かってくれません。","translation":"No matter how much I explain, they do not understand.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"いくら待ってもバスが来ません。","translation":"No matter how long I wait, the bus does not come.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0379":[{"text":"どの方法がいいかは目的によって違う。","translation":"Which method is best depends on the purpose.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"によって違う","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、どの方法がいいかは目的によって違う。","translation":"In fact, which method is best depends on the purpose.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"によって違う","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「どの方法がいいかは目的によって違う」と言った。","translation":"A friend said, “Which method is best depends on the purpose.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"によって違う","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0380":[],"jp-g-0381":[],"jp-g-0382":[],"jp-g-0383":[{"text":"川は美しいからといって尊いわけではない。","translation":"Just because a river is beautiful doesn't mean that it is precious.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"141357","matchedSignature":"わけではない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"付き合いがいやなわけではないが疲れているのだ。","translation":"I don't mean to be antisocial, but I'm tired.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"85026","matchedSignature":"わけではない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"それは定石通りというだけで、手を抜いたわけではないのです。","translation":"That's just standard practise, it's not like they're cutting corners.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"74194","matchedSignature":"わけではない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0384":[{"text":"彼が入ってきた、それと同時にベルが鳴った。","translation":"He came in, and at the same time the bell rang.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"119577","matchedSignature":"と同時に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"ベルが鳴ると同時に、学生が立ち上がった。","translation":"The students stood up at the same moment the bell rang.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"と同時に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、ベルが鳴ると同時に、学生が立ち上がった。","translation":"In fact, the students stood up at the same moment the bell rang.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"と同時に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0385":[{"text":"お菓子で赤ちゃんが窒息するところだった。","translation":"The baby almost choked on a piece of candy.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"227385","matchedSignature":"ところだった","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"二台の車は道路で正面衝突するところだった。","translation":"The two cars almost met head-on on the way.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"123048","matchedSignature":"ところだった","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"うっかりそれを忘れるところだったわ。","translation":"I almost forgot all about that.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"161315","matchedSignature":"ところだった","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0386":[],"jp-g-0387":[],"jp-g-0388":[{"text":"睡眠と健康には深い関係がある。","translation":"Sleep and health have a deep relationship.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"関係がある","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、睡眠と健康には深い関係がある。","translation":"In fact, sleep and health have a deep relationship.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"関係がある","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「睡眠と健康には深い関係がある」と言った。","translation":"A friend said, “Sleep and health have a deep relationship.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"関係がある","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0389":[{"text":"スコット教授の最後の批判に関しては、前回の回答で述べたこと以外に付け加えるものは何もない。","translation":"Regarding Professor Scott's final criticism I have nothing more to add to what I said in my previous reply.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"214695","matchedSignature":"に関して","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0390":[],"jp-g-0391":[],"jp-g-0392":[{"text":"私ができるのは待つくらいです。","translation":"About the only thing I can do is wait.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"休日にすることは本を読むくらいです。","translation":"About the only thing I do on days off is read books.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"私が知っているのは名前くらいです。","translation":"About the only thing I know is the name.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0393":[{"text":"さ、始めよう。","translation":"All right, let's begin.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"さ、次はどうする？","translation":"Well then, what shall we do next?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"さ、そろそろ行こうか。","translation":"All right, shall we get going?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0394":[{"text":"それがさ、昨日大変だったんだよ。","translation":"So, you know, yesterday was rough.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"俺さ、来月引っ越すんだ。","translation":"Me, you know, I'm moving next month.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"でもさ、それは違うと思う。","translation":"But, you know, I think that is different.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0395":[{"text":"大丈夫さ。","translation":"It'll be fine, you know.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"そんなの簡単さ。","translation":"Something like that is easy, you know.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"明日には終わるさ。","translation":"It'll be finished by tomorrow, you know.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0396":[],"jp-g-0397":[],"jp-g-0398":[],"jp-g-0399":[],"jp-g-0400":[],"jp-g-0401":[],"jp-g-0402":[],"jp-g-0403":[],"jp-g-0404":[],"jp-g-0405":[],"jp-g-0406":[],"jp-g-0407":[],"jp-g-0408":[{"text":"地球が丸いというのは事実だ。","translation":"It is a fact that the earth is round.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"というのは事実だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、地球が丸いというのは事実だ。","translation":"In fact, it is a fact that the earth is round.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"というのは事実だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「地球が丸いというのは事実だ」と言った。","translation":"A friend said, “It is a fact that the earth is round.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"というのは事実だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0409":[{"text":"我々の観点から言うと、彼の提案は妥当なものだ。","translation":"From our point of view, his proposal is reasonable.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"186303","matchedSignature":"から言うと","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"倫理の点から言うと、技術関連の大原則は「現在への責任」だが、「未来への責任」という新しい考え方が出てきた。","translation":"From an ethical point of view, the great principle of technology is \"responsibility to the present\" but the new way of thinking, \"responsibility to the future\" has emerged.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"75662","matchedSignature":"から言うと","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0410":[],"jp-g-0411":[],"jp-g-0412":[{"text":"私にとっては冬は楽しむというよりはむしろ耐える季節だ。","translation":"For me winter is rather something to be put up with than to be enjoyed.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"164770","matchedSignature":"というより","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼は小説家というよりもむしろ評論家です。","translation":"He is a critic rather than a novelist.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"104131","matchedSignature":"というより","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"その色はピンクというより紫だ。","translation":"The color is purple rather than pink.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"208891","matchedSignature":"というより","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0413":[{"text":"彼女は自転車にはもちろんオートバイにも乗れない。","translation":"She cannot ride a motorcycle, not to mention a bicycle.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"89129","matchedSignature":"はもちろん","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼女は自転車はもちろんのこと、オートバイにものれる。","translation":"She can ride a motorcycle, not to mention a bicycle.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"89125","matchedSignature":"はもちろん","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0414":[],"jp-g-0415":[{"text":"１９世紀末になって初めて植物の品種改良は科学の一分野となった。","translation":"Not until the end of the nineteenth century, did plant breeding become a scientific discipline.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"235865","matchedSignature":"て初めて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"日本に来て初めて刺身を食べたんだ。","translation":"It was not until I came to Japan that I ate sashimi.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"154734","matchedSignature":"て初めて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"オーストラリアへ行って初めて、日本はなんと小さい国かと実感した。","translation":"I didn't realize till I visited Australia how small Japan really is.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"227788","matchedSignature":"て初めて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0416":[],"jp-g-0417":[{"text":"水さえあれば生きられます。","translation":"As long as there is water, we can survive.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"時間さえあれば手伝えます。","translation":"If only I have time, I can help.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"このボタンを押しさえすれば動きます。","translation":"It will work as long as you press this button.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0418":[],"jp-g-0419":[],"jp-g-0420":[],"jp-g-0421":[],"jp-g-0422":[],"jp-g-0423":[],"jp-g-0424":[{"text":"まるで夢のようです。","translation":"It is just like a dream.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼はまるで何も知らないようです。","translation":"He acts as if he knows nothing.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"雪で町はまるで別世界のようでした。","translation":"Because of the snow, the town looked like a completely different world.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0425":[{"text":"彼がその秘密を知っているような気がする。","translation":"I have the impression that he knows the secret.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"120877","matchedSignature":"ような気がする","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0426":[{"text":"この荷物は重すぎて、とても一人では持てません。","translation":"This luggage is so heavy that I cannot possibly carry it alone.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この仕事は一日ではとても終わりません。","translation":"There is no way this work can be finished in one day.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"その値段ではとても買えません。","translation":"At that price, I simply cannot buy it.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0427":[],"jp-g-0428":[],"jp-g-0429":[],"jp-g-0430":[],"jp-g-0431":[],"jp-g-0432":[{"text":"正直が最善の方策であるのは言うまでもない。","translation":"It goes without saying that honesty is the best policy.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"142923","matchedSignature":"は言うまでもない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"正直が最良の策であるという事は言うまでもない。","translation":"It goes without saying that honesty is the best policy.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"142887","matchedSignature":"は言うまでもない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼らが間違っているのは言うまでもないことだ。","translation":"It goes without saying that they are in the wrong.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"98721","matchedSignature":"は言うまでもない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0433":[{"text":"約束は決して忘れません。","translation":"I will never forget the promise.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼は決して嘘をつきません。","translation":"He never tells lies.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"これは決して簡単ではありません。","translation":"This is by no means easy.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0434":[{"text":"私は彼の要望に応じるわけにはいかない。","translation":"I cannot comply with his request.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"153771","matchedSignature":"わけにはいかない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"僕はその問題を黙って見過ごすわけにはいかない。","translation":"I cannot silently overlook this problem.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"82060","matchedSignature":"わけにはいかない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"人間は鋳型に入れて作るわけにはいかない。","translation":"A man cannot be made in a mold.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"144255","matchedSignature":"わけにはいかない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0435":[],"jp-g-0436":[],"jp-g-0437":[],"jp-g-0438":[],"jp-g-0439":[],"jp-g-0440":[],"jp-g-0441":[{"text":"どちらかというと彼は物事を楽観する方だ。","translation":"He is rather optimistic.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"200819","matchedSignature":"かというと","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"今晩はどちらかというと映画に行くより家にいたい。","translation":"I would rather stay at home than go to the movies tonight.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"171247","matchedSignature":"かというと","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0442":[],"jp-g-0443":[],"jp-g-0444":[],"jp-g-0445":[],"jp-g-0446":[],"jp-g-0447":[],"jp-g-0448":[{"text":"この果物には強い甘みがあります。","translation":"This fruit has a strong sweetness.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"薬を飲んだら痛みが消えました。","translation":"The pain disappeared after I took medicine.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"このスープには深みのある味があります。","translation":"This soup has a deep, rich flavor.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0449":[{"text":"彼女はお姉さんと同じくらい親切だ。","translation":"She is no less kind than her sister is.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"93085","matchedSignature":"と同じくらい","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0450":[{"text":"兄と違って、弟はとても静かだ。","translation":"Unlike his older brother, the younger brother is very quiet.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"と違って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、兄と違って、弟はとても静かだ。","translation":"In fact, unlike his older brother, the younger brother is very quiet.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"と違って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「兄と違って、弟はとても静かだ」と言った。","translation":"A friend said, “Unlike his older brother, the younger brother is very quiet.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"と違って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0451":[],"jp-g-0452":[{"text":"私もそうだが、ＩＴ業界には宵っ張りの人が多いに違いない。","translation":"I'm one too, and I'm sure there are lots of night-owls in the IT world.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"74484","matchedSignature":"に違いない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0453":[],"jp-g-0454":[{"text":"インサイダー取引に当たる疑いが濃厚になってきた。","translation":"Suspicion that this amounts to insider trading has strengthened.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"76853","matchedSignature":"に当たる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0455":[],"jp-g-0456":[{"text":"理論と実践は相伴うとは限らない。","translation":"Theory and practice do not necessarily go together.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"78354","matchedSignature":"とは限らない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"理論と実践が伴うとは限らない。","translation":"Theory and practice do not necessarily go together.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"78356","matchedSignature":"とは限らない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"長年抱いていた夢が必ずしも叶うとは限らない。","translation":"Long-cherished dreams don't always come true.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"125855","matchedSignature":"とは限らない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0457":[],"jp-g-0458":[],"jp-g-0459":[],"jp-g-0460":[],"jp-g-0461":[{"text":"正直が最善の方策であるのは言うまでもない。","translation":"It goes without saying that honesty is the best policy.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"142923","matchedSignature":"言うまでもない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"言うまでもないことだが捜索は徒労に終わった。","translation":"It goes without saying, but the search ended in vain.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"76186","matchedSignature":"言うまでもない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"正直が最良の策であるという事は言うまでもない。","translation":"It goes without saying that honesty is the best policy.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"142887","matchedSignature":"言うまでもない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0462":[{"text":"勝利は得られそうもないが、不可能でもない。","translation":"Victory is unlikely but not impossible.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"147161","matchedSignature":"そうもない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0463":[],"jp-g-0464":[],"jp-g-0465":[{"text":"彼は英語を話し、また中国語も話せます。","translation":"He speaks English and also Chinese.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この店は安く、また駅からも近いです。","translation":"This shop is inexpensive and is also close to the station.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼女は研究者であり、また作家でもあります。","translation":"She is a researcher and also a writer.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0466":[],"jp-g-0467":[],"jp-g-0468":[],"jp-g-0469":[],"jp-g-0470":[{"text":"トムがテレビをつけたとたんにヒューズがとんだ。","translation":"No sooner had Tom turned on the TV than the fuse blew.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"200220","matchedSignature":"たとたんに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼がマッチをすったとたんに爆弾が爆発した。","translation":"No sooner had he struck the match than the bomb exploded.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"120713","matchedSignature":"たとたんに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼女を見たとたんに、彼は真っ青になった。","translation":"He turned pale the instant he saw her.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"86119","matchedSignature":"たとたんに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0471":[],"jp-g-0472":[],"jp-g-0473":[],"jp-g-0474":[],"jp-g-0475":[],"jp-g-0476":[{"text":"まず第一に、雑貨店を運営するには資金が不十分だ。","translation":"To begin with, the funds are not sufficient for running a grocery.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"195573","matchedSignature":"第一","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"第一に、それは正義の問題である。","translation":"Firstly, it is a matter of justice.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"137206","matchedSignature":"第一","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"第一四半期の企業収益は失望的な結果だった。","translation":"Corporate earnings for the first quarter were disappointing.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"137193","matchedSignature":"第一","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0477":[],"jp-g-0478":[{"text":"物価は上がる一方だ。","translation":"Prices keep rising.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"一方だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、物価は上がる一方だ。","translation":"In fact, prices keep rising.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"一方だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「物価は上がる一方だ」と言った。","translation":"A friend said, “Prices keep rising.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"一方だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0479":[{"text":"一部の住民が様子見の態度を取る一方で他の者は大洪水に備えた。","translation":"Some residents took a wait-and-see attitude while others prepared for heavy flooding.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"76346","matchedSignature":"一方で","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"この仕事は大変な一方で、やりがいもある。","translation":"This job is difficult, while at the same time it is rewarding.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"一方で","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、この仕事は大変な一方で、やりがいもある。","translation":"In fact, this job is difficult, while at the same time it is rewarding.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"一方で","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0480":[],"jp-g-0481":[],"jp-g-0482":[],"jp-g-0483":[{"text":"私はハリウッド映画の商業主義に懸念を抱かずにはいられない。","translation":"I cannot help but be concerned about the commercialism of Hollywood movies.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"75197","matchedSignature":"ずにはいられない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼女は欠点だらけだけど、好きにならずにはいられない。","translation":"I cannot help loving her in spite of her many faults.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"90320","matchedSignature":"ずにはいられない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"頭が痛いときは鎮痛剤を飲まずにはいられない。","translation":"I can't help taking painkillers when I have a headache.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"123869","matchedSignature":"ずにはいられない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0484":[],"jp-g-0485":[],"jp-g-0486":[{"text":"彼ほどの確立した科学者がそのような初歩的な誤りを犯すとは実際上考えられないことである。","translation":"It is practically unthinkable that a scientist of his stature would have made such an elementary mistake.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"98809","matchedSignature":"考えられない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼が嘘をつくなんて考えられない。","translation":"It is unthinkable that he would lie.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"考えられない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、彼が嘘をつくなんて考えられない。","translation":"In fact, it is unthinkable that he would lie.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"考えられない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0487":[{"text":"長年抱いていた夢が必ずしも叶うとは限らない。","translation":"Long-cherished dreams don't always come true.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"125855","matchedSignature":"必ずしも","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"ボクシングは必ずしも荒っぽいスポーツではない。","translation":"Boxing is not always a rough sport.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"196405","matchedSignature":"必ずしも","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"保守主義の人が必ずしも反動主義者とは限らない。","translation":"A conservative is not always a reactionary.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"83235","matchedSignature":"必ずしも","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0488":[{"text":"状況を確認し、対応を決めた。","translation":"We checked the situation and decided on a response.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼は立ち上がり、静かに部屋を出た。","translation":"He stood up and quietly left the room.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"資料を読み、要点をまとめる。","translation":"Read the materials and summarize the key points.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0489":[],"jp-g-0490":[],"jp-g-0491":[{"text":"一週間かけて報告書を書き上げた。","translation":"I finished writing the report over the course of a week.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"パンがきれいに焼き上がった。","translation":"The bread finished baking beautifully.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"チームで新しい仕組みを作り上げた。","translation":"The team built the new system to completion.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0492":[],"jp-g-0493":[],"jp-g-0494":[],"jp-g-0495":[],"jp-g-0496":[],"jp-g-0497":[],"jp-g-0498":[],"jp-g-0499":[],"jp-g-0500":[{"text":"その聖職者は人前では真面目なふりをする。","translation":"The priest pretends to be solemn in public.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"208647","matchedSignature":"ふりをする","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"その中の１人は俳優で、誰かを殺すふりをするのです。","translation":"One of them is an actor, who is going to pretend to murder someone.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"207846","matchedSignature":"ふりをする","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0501":[],"jp-g-0502":[],"jp-g-0503":[{"text":"結果が公表され次第、私は君にそれを知らせた。","translation":"I told you the result as soon as it was made public.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"175882","matchedSignature":"次第","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"結果が公表され次第お知らせします。","translation":"I'll let you know the result as soon as it is made public.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"175881","matchedSignature":"次第","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0504":[],"jp-g-0505":[],"jp-g-0506":[{"text":"彼女はどうしても彼を部屋にいれようとしなかった。","translation":"She wouldn't let him in the room no matter what.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"92023","matchedSignature":"どうしても","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0507":[],"jp-g-0508":[{"text":"懐中電灯は、船舶同士とか、街の通りを走っている自動車に向けて合図を伝える。","translation":"Flashing lights transmit messages between ships and to motorists along city streets.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"185148","matchedSignature":"同士","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"進路を開拓するという同じ目標を持った仲間同士が協力する。","translation":"Companions with the same aim, to carve out their own future, cooperate with each other.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"75034","matchedSignature":"同士","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"人間同士が戦うところを天使が空から眺めている。","translation":"Angels watch from above as men fight amongst themselves.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"144228","matchedSignature":"同士","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0509":[],"jp-g-0510":[],"jp-g-0511":[{"text":"犬と猫を比べると、前者は活発で、後者は静かだ。","translation":"Comparing dogs and cats, the former are active and the latter are quiet.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"前者は","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「犬と猫を比べると、前者は活発で、後者は静かだ」と言った。","translation":"A friend said, “Comparing dogs and cats, the former are active and the latter are quiet.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"前者は","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、犬と猫を比べると、前者は活発で、後者は静かだ。","translation":"In fact, comparing dogs and cats, the former are active and the latter are quiet.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"前者は","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0512":[],"jp-g-0513":[],"jp-g-0514":[],"jp-g-0515":[],"jp-g-0516":[],"jp-g-0517":[],"jp-g-0518":[],"jp-g-0519":[],"jp-g-0520":[{"text":"洋子は一体どこへ行ってしまったのだろう。","translation":"Where can Yoko have gone?","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"78878","matchedSignature":"一体","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"一体何が彼らをそのような行動に駆り立てたのか？","translation":"What on earth spurred them to such an action?","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"75503","matchedSignature":"一体","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0521":[],"jp-g-0522":[],"jp-g-0523":[{"text":"我々は綿の代わりにピーナッツを植えた。","translation":"We planted peanuts instead of cotton.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"185519","matchedSignature":"代わりに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼女は私の代わりにその会合に出席するでしょう。","translation":"She will attend the meeting instead of me.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"89339","matchedSignature":"代わりに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"私たちはナイフとフォークの代わりに箸を使う。","translation":"We use chopsticks in place of knives and forks.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"166259","matchedSignature":"代わりに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0524":[{"text":"副大統領は大統領に代わって式典に出席した。","translation":"The vice-president attended the ceremony on behalf of the president.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"83900","matchedSignature":"に代わって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼女に代わって誰が会合に出席するのか。","translation":"Who will attend the meeting on her behalf?","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"94790","matchedSignature":"に代わって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0525":[],"jp-g-0526":[{"text":"彼は健康が衰えつつあるという理由で辞職したがっている。","translation":"He wishes to resign on the grounds that his health is failing.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"107763","matchedSignature":"という理由で","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼女は欠勤がちだという理由で首になった。","translation":"She was fired on the grounds that she was often absent.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"90323","matchedSignature":"という理由で","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"体調が悪いという理由で、彼は早退した。","translation":"He left early on the grounds that he was feeling unwell.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"という理由で","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0527":[{"text":"高い関税が国際貿易の障害となっている。","translation":"High tariffs have become a barrier to international trade.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"173258","matchedSignature":"となっている","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"ドルが円をはじめとする主要なアジア通貨に対して急落しているなか、実質上のドルペッグ政策を採っている中国の人民元は割安となっている。","translation":"In the midst of the dollar falling hard against the Yen and other major Eastern currencies the Chinese Yuan, with China effectively taking a 'dollar peg' policy, has become cheap.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"75108","matchedSignature":"となっている","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0528":[{"text":"新聞は世の動向を左右する。","translation":"Newspapers influence the current of time.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"145130","matchedSignature":"左右する","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"睡眠時間は集中力を左右する。","translation":"The amount of sleep influences concentration.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"左右する","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、睡眠時間は集中力を左右する。","translation":"In fact, the amount of sleep influences concentration.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"左右する","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0529":[],"jp-g-0530":[],"jp-g-0531":[{"text":"それゆえここにとどまらざるを得ないだろう。","translation":"Hence, I shall have to stay here.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"204782","matchedSignature":"ざるを得ない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼らは彼のわずかな収入で暮らさざるを得ない。","translation":"They have to live on his small income.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"96352","matchedSignature":"ざるを得ない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0532":[],"jp-g-0533":[],"jp-g-0534":[],"jp-g-0535":[],"jp-g-0536":[],"jp-g-0537":[],"jp-g-0538":[{"text":"彼らは計画全体をあきらめるよりほかないと意見が一致している。","translation":"They agree that they have no choice but to give up the whole plan.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"97284","matchedSignature":"よりほかない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、彼らは計画全体をあきらめるよりほかないと意見が一致している。","translation":"In fact, they agree that they have no choice but to give up the whole plan.","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"よりほかない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「彼らは計画全体をあきらめるよりほかないと意見が一致している」と言った。","translation":"A friend said, “They agree that they have no choice but to give up the whole plan.”","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"よりほかない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0539":[],"jp-g-0540":[{"text":"一応、予約を確認しておいた。","translation":"I checked the reservation just in case.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"一応","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、一応、予約を確認しておいた。","translation":"In fact, i checked the reservation just in case.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"一応","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「一応、予約を確認しておいた」と言った。","translation":"A friend said, “I checked the reservation just in case.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"一応","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0541":[{"text":"準備は一応できている。","translation":"The preparations are more or less complete.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"一応","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、準備は一応できている。","translation":"In fact, the preparations are more or less complete.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"一応","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「準備は一応できている」と言った。","translation":"A friend said, “The preparations are more or less complete.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"一応","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0542":[{"text":"彼が犯人に相違ない。","translation":"He is without a doubt the culprit.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に相違ない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、彼が犯人に相違ない。","translation":"In fact, he is without a doubt the culprit.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に相違ない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「彼が犯人に相違ない」と言った。","translation":"A friend said, “He is without a doubt the culprit.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に相違ない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0543":[{"text":"万が一に備えて、武器になるものを探した。","translation":"I looked around for a weapon just in case.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"81205","matchedSignature":"万が一","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"万が一遅れる場合は、連絡してください。","translation":"In the unlikely event that you are late, please contact me.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"万が一","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、万が一遅れる場合は、連絡してください。","translation":"In fact, in the unlikely event that you are late, please contact me.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"万が一","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0544":[],"jp-g-0545":[{"text":"世界の歴史は自由意識の進歩にほかならない。","translation":"The history of the world is none other than the progress of the consciousness of freedom.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"143420","matchedSignature":"にほかならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、世界の歴史は自由意識の進歩にほかならない。","translation":"In fact, the history of the world is none other than the progress of the consciousness of freedom.","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"にほかならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「世界の歴史は自由意識の進歩にほかならない」と言った。","translation":"A friend said, “The history of the world is none other than the progress of the consciousness of freedom.”","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"にほかならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0546":[],"jp-g-0547":[],"jp-g-0548":[],"jp-g-0549":[{"text":"こつを心得ている人に任せるのが、一番いいだろう。","translation":"It would be best to leave it to a man who knows the ropes.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"224094","matchedSignature":"に任せる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"娘が卒業した後は自分の好きに任せることにきめた。","translation":"We have decided to leave our daughter to herself after she left school.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"80843","matchedSignature":"に任せる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"パーティーの事はみんな君に任せるよ。","translation":"I will leave everything about the party up to you.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"198468","matchedSignature":"に任せる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0550":[],"jp-g-0551":[],"jp-g-0552":[],"jp-g-0553":[],"jp-g-0554":[],"jp-g-0555":[{"text":"世界の人口は産業革命以来、３倍以上になった。","translation":"Since the Industrial Revolution, the world population has more than tripled.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"143428","matchedSignature":"以上","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼はそれ以上怒りを堪える事が出来なかった。","translation":"He couldn't keep his temper any longer.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"112152","matchedSignature":"以上","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"もうこれ以上延ばすわけにはいかない。","translation":"I can't put it off any longer.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"194466","matchedSignature":"以上","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0556":[{"text":"その山は海抜3,000メートル以上にある。","translation":"The mountain is more than 3,000 meters above sea level.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"210448","matchedSignature":"以上に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"世界の人口は産業革命以来、３倍以上になった。","translation":"Since the Industrial Revolution, the world population has more than tripled.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"143428","matchedSignature":"以上に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"今まで以上にいっそう勉強に励みなさい。","translation":"You should study even more than before.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"172576","matchedSignature":"以上に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0557":[],"jp-g-0558":[],"jp-g-0559":[{"text":"東京を中心にイベントが開かれる。","translation":"Events will be held mainly around Tokyo.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を中心に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、東京を中心にイベントが開かれる。","translation":"In fact, events will be held mainly around Tokyo.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を中心に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「東京を中心にイベントが開かれる」と言った。","translation":"A friend said, “Events will be held mainly around Tokyo.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を中心に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0560":[],"jp-g-0561":[],"jp-g-0562":[],"jp-g-0563":[],"jp-g-0564":[{"text":"あの信号の手前で降ろしてください。","translation":"Please let me off on this side of that traffic light.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"230827","matchedSignature":"手前","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"みんなの手前、弱音は吐けない。","translation":"In front of everyone, I cannot show weakness.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"手前","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、みんなの手前、弱音は吐けない。","translation":"In fact, in front of everyone, I cannot show weakness.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"手前","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0565":[],"jp-g-0566":[{"text":"野球への興味はわが国ではあらゆる階層、年齢にわたっている。","translation":"Interest in baseball cuts across classes and ages in this country.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"79638","matchedSignature":"にわたって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"生徒の年齢は１８歳から２５歳にわたっている。","translation":"The students range in age from 18 to 25.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"142731","matchedSignature":"にわたって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"最終試験でボブは全くひどい目にあった。出題範囲が講義の全てにわたっていたのだ。","translation":"At his final exam, Bob was really put through the wringer; the test covered everything that was in the course.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"170518","matchedSignature":"にわたって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0567":[{"text":"彼らはアフリカの西海岸に沿って航海した。","translation":"They sailed along the west coast of Africa.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"98225","matchedSignature":"に沿って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼は通りに沿って車を運転していた。","translation":"He was driving a car along the street.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"102010","matchedSignature":"に沿って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"通りに沿って桜が植えられている。","translation":"Cherry trees are planted along the street.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"125644","matchedSignature":"に沿って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0568":[],"jp-g-0569":[{"text":"君の命令にしたがって私はボートを売ろう。","translation":"I will sell the boat in accordance with your orders.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"178032","matchedSignature":"にしたがって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0570":[{"text":"人口の増加に伴って、交通問題も深刻になった。","translation":"Along with population growth, traffic problems also became serious.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に伴って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、人口の増加に伴って、交通問題も深刻になった。","translation":"In fact, along with population growth, traffic problems also became serious.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に伴って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「人口の増加に伴って、交通問題も深刻になった」と言った。","translation":"A friend said, “Along with population growth, traffic problems also became serious.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に伴って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0571":[],"jp-g-0572":[],"jp-g-0573":[],"jp-g-0574":[{"text":"兵士達は警戒しながら国境に向かって進んだ。","translation":"The soldiers headed for the frontier with caution.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"83588","matchedSignature":"に向かって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"台風は発達しながら九州方面に向かっています。","translation":"The typhoon is gaining strength as it heads for Kyushu.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"137774","matchedSignature":"に向かって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0575":[{"text":"たいていの親は自分の子供の将来が気になるものです。","translation":"Parents are usually concerned about their children's future.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"203945","matchedSignature":"が気になる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0576":[{"text":"もし私があなたなら、もっと体に気をつけるだろう。","translation":"I would be more careful if I were you.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"193665","matchedSignature":"に気をつける","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"私達は彼女に気をつけるように叫んだ。","translation":"We yelled at her to take care.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"151310","matchedSignature":"に気をつける","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0577":[{"text":"彼は周囲の反対も構わず、計画を進めた。","translation":"He proceeded with the plan without regard for opposition around him.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"も構わず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、彼は周囲の反対も構わず、計画を進めた。","translation":"In fact, he proceeded with the plan without regard for opposition around him.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"も構わず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「彼は周囲の反対も構わず、計画を進めた」と言った。","translation":"A friend said, “He proceeded with the plan without regard for opposition around him.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"も構わず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0578":[],"jp-g-0579":[],"jp-g-0580":[],"jp-g-0581":[{"text":"結婚式は天候にかかわらず催されるだろう。","translation":"The wedding ceremony will be held regardless of the weather.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"74784","matchedSignature":"にかかわらず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"年齢にかかわらず全ての人々が許可されます。","translation":"Every person will be admitted regardless of his or her age.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"121784","matchedSignature":"にかかわらず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0582":[{"text":"晴天にもかかわらず、空気は冷え冷えとしていた。","translation":"In spite of the sunny weather, the air was rather chilly.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"142993","matchedSignature":"にもかかわらず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼女は吹雪にもかかわらず時間どおりに学校についた。","translation":"She arrived at school on time in spite of the snowstorm.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"88441","matchedSignature":"にもかかわらず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"名声にもかかわらず、彼は幸せではない。","translation":"Despite all his fame, he is not happy.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"80797","matchedSignature":"にもかかわらず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0583":[{"text":"急いでいる日に限って、電車が遅れる。","translation":"The train is late particularly on days when I am in a hurry.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に限って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、急いでいる日に限って、電車が遅れる。","translation":"In fact, the train is late particularly on days when I am in a hurry.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に限って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「急いでいる日に限って、電車が遅れる」と言った。","translation":"A friend said, “The train is late particularly on days when I am in a hurry.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に限って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0584":[],"jp-g-0585":[],"jp-g-0586":[],"jp-g-0587":[],"jp-g-0588":[],"jp-g-0589":[{"text":"音は静まり次第に消えて行った。","translation":"The music gradually died away.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"188314","matchedSignature":"次第に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"人々は次第に本来の目的を見失うだろう。","translation":"People will gradually lose sight of the original purpose.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"144106","matchedSignature":"次第に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0590":[],"jp-g-0591":[{"text":"その試合には国籍のいかんを問わず誰でも参加出来る。","translation":"Anyone can participate in the game, no matter what nationality they are.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"210037","matchedSignature":"を問わず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0592":[],"jp-g-0593":[],"jp-g-0594":[{"text":"要するに、借金を踏み倒して逃げちまった。","translation":"In short, he's run off without paying off his debt.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"75402","matchedSignature":"要するに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"要するに、彼はあまりにも正直すぎた。","translation":"In short, he was too honest.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"78824","matchedSignature":"要するに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0595":[{"text":"実物を見てからでないと、決められません。","translation":"I cannot decide until I have seen the actual item.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"てからでないと","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、実物を見てからでないと、決められません。","translation":"In fact, i cannot decide until I have seen the actual item.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"てからでないと","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「実物を見てからでないと、決められません」と言った。","translation":"A friend said, “I cannot decide until I have seen the actual item.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"てからでないと","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0596":[],"jp-g-0597":[],"jp-g-0598":[{"text":"彼を見ると、笑わないではいられないだろう。","translation":"To look at him, you couldn't help laughing.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"95901","matchedSignature":"ないではいられない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"私は彼の正直さを疑わないではいられない。","translation":"I can't help doubting his honesty.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"153841","matchedSignature":"ないではいられない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"私は彼の食欲に感心しないではいられない。","translation":"I cannot help admiring his appetite.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"153861","matchedSignature":"ないではいられない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0599":[{"text":"冬がきたので、たくさんの燃料を買わねばならない。","translation":"With winter coming on, they have to buy a lot of fuel.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"124395","matchedSignature":"ねばならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"あなたは多くの困難に絶え抜かねばならない。","translation":"You have to go through many hardships.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"231763","matchedSignature":"ねばならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼は毎日血圧を計ってもらわねばならない。","translation":"He has to have his blood pressure taken every day.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"99784","matchedSignature":"ねばならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0600":[],"jp-g-0601":[],"jp-g-0602":[],"jp-g-0603":[],"jp-g-0604":[{"text":"入学に際して、必要な書類を提出してください。","translation":"On the occasion of enrollment, please submit the required documents.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に際して","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、入学に際して、必要な書類を提出してください。","translation":"In fact, on the occasion of enrollment, please submit the required documents.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に際して","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「入学に際して、必要な書類を提出してください」と言った。","translation":"A friend said, “On the occasion of enrollment, please submit the required documents.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に際して","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0605":[],"jp-g-0606":[],"jp-g-0607":[{"text":"退職を契機に茶道を始めた。","translation":"I took the opportunity of retirement to begin studying the tea ceremony.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"75903","matchedSignature":"を契機に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"留学を契機に、将来について考え始めた。","translation":"Studying abroad became the trigger for me to think about my future.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を契機に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、留学を契機に、将来について考え始めた。","translation":"In fact, studying abroad became the trigger for me to think about my future.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を契機に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0608":[],"jp-g-0609":[],"jp-g-0610":[{"text":"私が講堂に入るか入らないかのうちに式が始まった。","translation":"No sooner had I entered the hall than the ceremony began.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"167746","matchedSignature":"ないかのうちに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0611":[],"jp-g-0612":[],"jp-g-0613":[],"jp-g-0614":[],"jp-g-0615":[],"jp-g-0616":[],"jp-g-0617":[{"text":"本を読んではメモを取り、また読んでは考えました。","translation":"I repeatedly read, took notes, and then read and thought again.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"雨が降っては止み、降っては止んでいます。","translation":"The rain keeps starting and stopping.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"子どもは立っては座り、立っては座りしていました。","translation":"The child repeatedly stood up and sat down.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0618":[],"jp-g-0619":[{"text":"市長は調査の結果を公表すると宣言した。","translation":"The mayor declared that he would announce the result of the investigation.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"168323","matchedSignature":"の結果","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"このことから、大規模な人口移動は経済変化の結果ではないという議論を導くことができる。","translation":"From this we can derive the argument that major population shifts are not the result of economic change.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"223791","matchedSignature":"の結果","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"人質の運命はその交渉の結果にかかっている。","translation":"The fate of the hostages depends on the result of the negotiation.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"144197","matchedSignature":"の結果","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0620":[{"text":"世界の人口は産業革命以来、３倍以上になった。","translation":"Since the Industrial Revolution, the world population has more than tripled.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"143428","matchedSignature":"以来","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"マリガンは１４ヶ月前に逆転で王座を奪取して以来、まったくの負けしらずです。","translation":"Mulligan has been riding high since he seized the crown in a come-from-behind victory 14 months ago.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"195172","matchedSignature":"以来","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"その協会は設立以来、素人の入会を断ってきた。","translation":"The association has excluded amateurs ever since its foundation.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"211427","matchedSignature":"以来","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0621":[],"jp-g-0622":[],"jp-g-0623":[{"text":"毎日練習した甲斐があった。","translation":"All the daily practice paid off.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"遠くから来た甲斐がありました。","translation":"It was worth coming from far away.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"努力の甲斐があって、試験に合格した。","translation":"Thanks to the effort paying off, I passed the exam.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0624":[],"jp-g-0625":[{"text":"したがって生産費を削る必要がある。","translation":"Therefore, it is necessary to reduce the cost.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"216172","matchedSignature":"したがって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"したがって、世界平和のためには、私達全てが地球という惑星の住人なのだ、という意識を絶え間ない国際的文化及び経済交流によって育成していかなければならない。","translation":"For world peace, therefore, we must develop the consciousness that we are all one people of planet Earth through continual international cultural and economic exchange.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"216173","matchedSignature":"したがって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0626":[],"jp-g-0627":[],"jp-g-0628":[{"text":"いびきにかけては、スノーさんにかなうものはいない。","translation":"When it comes to snoring, no one can top Mr Snore.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"228567","matchedSignature":"にかけては","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"数学にかけては彼はクラスの誰にも引けを取らない。","translation":"When it comes to mathematics, he is second to none in his class.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"143569","matchedSignature":"にかけては","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0629":[],"jp-g-0630":[],"jp-g-0631":[],"jp-g-0632":[],"jp-g-0633":[],"jp-g-0634":[{"text":"数字を足したり引いたりという面倒臭い仕事も一旦始めてしまえば、それはそれで面白さがあるものだよ。","translation":"Once you go ahead and start, even the tiresome work of adding and subtracting figures is interesting in its way.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"143540","matchedSignature":"一旦","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0635":[{"text":"低賃金、劣悪な労働条件、一方的な首切りなどの経済・労働問題はもとより、各種の人道的問題までも引き起こしている。","translation":"Of course, they are suffering from terrible working conditions such as low wages and arbitrary layoffs, as well as from various forms of discrimination.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"125549","matchedSignature":"はもとより","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0636":[],"jp-g-0637":[{"text":"彼らは彼の意志に反して彼にその契約書に署名させた。","translation":"They made him sign the contract against his will.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"96349","matchedSignature":"に反して","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼らの上司は彼らの意志に反して彼らを働かせた。","translation":"Their boss made them work against their will.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"98476","matchedSignature":"に反して","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"予想に反して、試験は簡単だった。","translation":"Contrary to expectations, the exam was easy.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に反して","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0638":[],"jp-g-0639":[{"text":"それは値段は安いが、その反面品質がよくない。","translation":"It is cheap, but on the other hand it is not good.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"204988","matchedSignature":"反面","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"この仕事は自由な反面、責任も重い。","translation":"This job offers freedom, but on the other hand it carries heavy responsibility.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"反面","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、この仕事は自由な反面、責任も重い。","translation":"In fact, this job offers freedom, but on the other hand it carries heavy responsibility.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"反面","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0640":[],"jp-g-0641":[],"jp-g-0642":[],"jp-g-0643":[{"text":"もしあなたが試験でカンニングをやってもそれで何の咎めも受けずに済むと思っているなら、とんでもない話だ。","translation":"If you think you can get away with cheating on the exam, you've got another thing coming.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"193922","matchedSignature":"ずに済む","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、もしあなたが試験でカンニングをやってもそれで何の咎めも受けずに済むと思っているなら、とんでもない話だ。","translation":"In fact, if you think you can get away with cheating on the exam, you've got another thing coming.","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"ずに済む","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「もしあなたが試験でカンニングをやってもそれで何の咎めも受けずに済むと思っているなら、とんでもない話だ」と言った。","translation":"A friend said, “If you think you can get away with cheating on the exam, you've got another thing coming.”","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"ずに済む","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0644":[{"text":"郵便局では、郵便は、行き先に応じて分類される。","translation":"In the post office, mail is classified according to the place where it is to go.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"79180","matchedSignature":"に応じて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"年齢に応じて、運動量を調整する。","translation":"Adjust the amount of exercise according to age.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に応じて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、年齢に応じて、運動量を調整する。","translation":"In fact, adjust the amount of exercise according to age.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に応じて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0645":[{"text":"彼を通して私は町の有力者と知り合いになった。","translation":"Through him I got acquainted with the big names of the town.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"95807","matchedSignature":"を通して","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"望遠鏡を通してみると、惑星はまったく新たな様相を呈する。","translation":"Seen through a telescope, the planets take on a completely new appearance.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"82485","matchedSignature":"を通して","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"それは誰を通して苦情を申し出ればいいのですか。","translation":"Through whom am I to make my complaint, then?","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"204992","matchedSignature":"を通して","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0646":[],"jp-g-0647":[],"jp-g-0648":[],"jp-g-0649":[{"text":"行くにしても行かないにしても、早く決めてください。","translation":"Whether you go or not, please decide quickly.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"買うにしても借りるにしても、お金が必要です。","translation":"Whether you buy or rent, you need money.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"賛成にしても反対にしても、理由を説明してください。","translation":"Whether you agree or disagree, please explain your reason.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0650":[],"jp-g-0651":[],"jp-g-0652":[],"jp-g-0653":[{"text":"知らぬ人について行ってはいけない。","translation":"You must not follow a person you do not know.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"終わらぬ戦いが続いた。","translation":"The unending battle continued.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"予期せぬ出来事が起きた。","translation":"An unexpected event occurred.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0654":[],"jp-g-0655":[],"jp-g-0656":[],"jp-g-0657":[],"jp-g-0658":[{"text":"雨がやんだかと思ったら、また降り始めた。","translation":"Just when I thought the rain had stopped, it started again.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"かと思ったら","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、雨がやんだかと思ったら、また降り始めた。","translation":"In fact, just when I thought the rain had stopped, it started again.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"かと思ったら","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「雨がやんだかと思ったら、また降り始めた」と言った。","translation":"A friend said, “Just when I thought the rain had stopped, it started again.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"かと思ったら","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0659":[{"text":"ご確認いただければと思います。","translation":"I would appreciate it if you could check it.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ばと思います","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、ご確認いただければと思います。","translation":"In fact, i would appreciate it if you could check it.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ばと思います","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「ご確認いただければと思います」と言った。","translation":"A friend said, “I would appreciate it if you could check it.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ばと思います","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0660":[{"text":"高ければ品質がいいというものでもない。","translation":"A higher price does not necessarily mean better quality.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"というものでもない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、高ければ品質がいいというものでもない。","translation":"In fact, a higher price does not necessarily mean better quality.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"というものでもない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「高ければ品質がいいというものでもない」と言った。","translation":"A friend said, “A higher price does not necessarily mean better quality.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"というものでもない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0661":[{"text":"この変化は重要だと考えられる。","translation":"This change can be considered important.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"と考えられる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、この変化は重要だと考えられる。","translation":"In fact, this change can be considered important.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"と考えられる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「この変化は重要だと考えられる」と言った。","translation":"A friend said, “This change can be considered important.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"と考えられる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0662":[{"text":"安全性という点から考えると、この案が最適だ。","translation":"From the standpoint of safety, this plan is best.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"という点から考えると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、安全性という点から考えると、この案が最適だ。","translation":"In fact, from the standpoint of safety, this plan is best.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"という点から考えると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「安全性という点から考えると、この案が最適だ」と言った。","translation":"A friend said, “From the standpoint of safety, this plan is best.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"という点から考えると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0663":[],"jp-g-0664":[],"jp-g-0665":[{"text":"彼は「あとで連絡する」という風に答えた。","translation":"He answered in a way that was like saying, “I will contact you later.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"という風に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、彼は「あとで連絡する」という風に答えた。","translation":"In fact, he answered in a way that was like saying, “I will contact you later.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"という風に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「彼は「あとで連絡する」という風に答えた」と言った。","translation":"A friend said, “He answered in a way that was like saying, “I will contact you later.”.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"という風に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0666":[],"jp-g-0667":[],"jp-g-0668":[{"text":"飛行機から見ると、小さな丘陵は平地のように見える。","translation":"Small hills look flat from an airplane.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"85739","matchedSignature":"から見ると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"飛行機から見ると、その島は巨大なクモのように見える。","translation":"Seen from an airplane, the island looks like a big spider.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"85738","matchedSignature":"から見ると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"さらに、横から見ると、前歯は出っ歯の状態にあります。","translation":"Moreover, when viewed from the side, the front teeth are protruding.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"74334","matchedSignature":"から見ると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0669":[{"text":"彼女がその知らせに興奮しないところを見ると、それを知っていたに違いない。","translation":"Seeing that she was not excited at the news, she must have known it.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"95646","matchedSignature":"ところを見ると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"フランス語を流暢に話すところを見ると、彼女はフランスで勉強したかもしれない。","translation":"Seeing as she can speak French fluently, she may have studied in France.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"196966","matchedSignature":"ところを見ると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、彼女がその知らせに興奮しないところを見ると、それを知っていたに違いない。","translation":"In fact, seeing that she was not excited at the news, she must have known it.","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"ところを見ると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0670":[{"text":"彼の様子からすると、疲れているとみえる。","translation":"Judging from how he looks, he seems to be tired.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"からすると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、彼の様子からすると、疲れているとみえる。","translation":"In fact, judging from how he looks, he seems to be tired.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"からすると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「彼の様子からすると、疲れているとみえる」と言った。","translation":"A friend said, “Judging from how he looks, he seems to be tired.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"からすると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0671":[],"jp-g-0672":[{"text":"川は美しいからといって尊いわけではない。","translation":"Just because a river is beautiful doesn't mean that it is precious.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"141357","matchedSignature":"からといって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"試験に失敗したからといって恥じる必要はない。","translation":"You needn't be ashamed because you failed the exam.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"151109","matchedSignature":"からといって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"栄養があるからといって食べられるものではない。","translation":"You can't eat it just because it is nutritious.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"189282","matchedSignature":"からといって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0673":[{"text":"そういえば、確かに太郎を見かけました。","translation":"Come to think of it, I did see Taro.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"213906","matchedSignature":"そういえば","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0674":[{"text":"少々お待ち願います。","translation":"Please wait a moment.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"こちらにお名前をご記入願います。","translation":"Please write your name here.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"会場では静かにお過ごし願います。","translation":"Please remain quiet in the venue.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0675":[],"jp-g-0676":[],"jp-g-0677":[],"jp-g-0678":[{"text":"彼はまるで父親に会ったことがないかのようだ。","translation":"It seems like he had never met his father before.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"110708","matchedSignature":"かのようだ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、彼はまるで父親に会ったことがないかのようだ。","translation":"In fact, it seems like he had never met his father before.","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"かのようだ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「彼はまるで父親に会ったことがないかのようだ」と言った。","translation":"A friend said, “It seems like he had never met his father before.”","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"かのようだ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0679":[],"jp-g-0680":[{"text":"努力したのだから、成功して当然だ。","translation":"Since you worked hard, it is only natural that you succeeded.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"て当然だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、努力したのだから、成功して当然だ。","translation":"In fact, since you worked hard, it is only natural that you succeeded.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"て当然だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「努力したのだから、成功して当然だ」と言った。","translation":"A friend said, “Since you worked hard, it is only natural that you succeeded.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"て当然だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0681":[{"text":"亭主が女房の尻にしかれるのも当然だ。","translation":"No wonder he is a henpecked husband.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"125552","matchedSignature":"のも当然だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"疲れているのも当然だ。","translation":"It is only natural that you are tired.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"のも当然だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、疲れているのも当然だ。","translation":"In fact, it is only natural that you are tired.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"のも当然だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0682":[],"jp-g-0683":[{"text":"警察に捕まるような恐れがあるのですか。","translation":"Is there any risk of being caught by the police?","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"176271","matchedSignature":"恐れがある","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0684":[],"jp-g-0685":[],"jp-g-0686":[],"jp-g-0687":[{"text":"そんな計画は失敗するに決まっている。","translation":"Such a plan is bound to fail.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"204155","matchedSignature":"に決まっている","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0688":[{"text":"新しい法案では大気汚染を６０％減少させることになっている。","translation":"The new law is expected to cut air pollution by 60%.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"145331","matchedSignature":"ことになっている","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0689":[{"text":"今日は出かける気がしない。","translation":"I do not feel like going out today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"本気でやる気がありますか。","translation":"Are you genuinely motivated to do it?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼は謝る気がない。","translation":"He has no intention of apologizing.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0690":[{"text":"彼は不安げな顔をしていた。","translation":"He had an anxious-looking expression.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼女は寂しげに笑った。","translation":"She smiled with a lonely air.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"子どもが得意げに話している。","translation":"The child is speaking proudly.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0691":[],"jp-g-0692":[],"jp-g-0693":[{"text":"電車が遅れたものですから、遅刻しました。","translation":"I was late because the train was delayed.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ものですから","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、電車が遅れたものですから、遅刻しました。","translation":"In fact, i was late because the train was delayed.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ものですから","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「電車が遅れたものですから、遅刻しました」と言った。","translation":"A friend said, “I was late because the train was delayed.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ものですから","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0694":[],"jp-g-0695":[{"text":"冬は運動不足になる傾向がある。","translation":"There is a tendency to get too little exercise in winter.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"傾向がある","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、冬は運動不足になる傾向がある。","translation":"In fact, there is a tendency to get too little exercise in winter.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"傾向がある","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「冬は運動不足になる傾向がある」と言った。","translation":"A friend said, “There is a tendency to get too little exercise in winter.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"傾向がある","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0696":[{"text":"彼女の勤勉はまったく賞賛に値する。","translation":"Her diligence is indeed worthy of praise.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"94507","matchedSignature":"に値する","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0697":[],"jp-g-0698":[{"text":"給料は低いが、仕事があるだけましだ。","translation":"The pay is low, but at least having a job is better than nothing.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"だけましだ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、給料は低いが、仕事があるだけましだ。","translation":"In fact, the pay is low, but at least having a job is better than nothing.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"だけましだ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「給料は低いが、仕事があるだけましだ」と言った。","translation":"A friend said, “The pay is low, but at least having a job is better than nothing.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"だけましだ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0699":[{"text":"幸いなことに、けが人はいなかった。","translation":"Fortunately, no one was injured.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"幸いなことに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、幸いなことに、けが人はいなかった。","translation":"In fact, fortunately, no one was injured.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"幸いなことに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「幸いなことに、けが人はいなかった」と言った。","translation":"A friend said, “Fortunately, no one was injured.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"幸いなことに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0700":[],"jp-g-0701":[],"jp-g-0702":[{"text":"行きたいことは行きたいが、時間がありません。","translation":"It is true that I want to go, but I do not have time.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"分かることは分かるが、納得はできません。","translation":"It is true that I understand, but I cannot accept it.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"安いことは安いが、品質が心配です。","translation":"It is true that it is cheap, but I am worried about the quality.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0703":[],"jp-g-0704":[],"jp-g-0705":[],"jp-g-0706":[],"jp-g-0707":[],"jp-g-0708":[],"jp-g-0709":[],"jp-g-0710":[{"text":"彼女は、心に愛情と優しさを込めてお祈りをした。","translation":"She said her prayers, her heart full of love and tenderness.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"93720","matchedSignature":"を込めて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"家では赤味がかった髪とそばかすのせいで、母が侮蔑を込めて「にんじん」と名付け、皆にもそう呼ばせています。","translation":"At home, because of his reddish hair and freckles, his mother scornfully named him \"carrot\" and had everybody else call him that.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"76297","matchedSignature":"を込めて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0711":[{"text":"私たちには材料に加えて見本も必要だ。","translation":"We need a sample in addition to materials.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"167155","matchedSignature":"に加えて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0712":[{"text":"私は君に何から何まで恩恵を受けている。","translation":"I owe everything to you.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"157455","matchedSignature":"何から何まで","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"旅行の準備は何から何まで彼女がしてくれた。","translation":"She took care of absolutely everything for the trip.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"何から何まで","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、旅行の準備は何から何まで彼女がしてくれた。","translation":"In fact, she took care of absolutely everything for the trip.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"何から何まで","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0713":[{"text":"よしあしは別としてとにかくやってみよう。","translation":"Whether it's good or not, let's do it anyway.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"192739","matchedSignature":"は別として","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼は時々出張することは別としてあまり旅をしない。","translation":"He doesn't travel much apart from occasional business trips.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"105278","matchedSignature":"は別として","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"費用は別として、その橋を築くには長い時間がかかるだろう。","translation":"Apart from the cost, it will take long to build the bridge.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"85793","matchedSignature":"は別として","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0714":[],"jp-g-0715":[],"jp-g-0716":[{"text":"専門家だけあって彼はその分野に詳しい。","translation":"As may be expected of an expert, he's well versed in the field.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"141414","matchedSignature":"だけあって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0717":[],"jp-g-0718":[],"jp-g-0719":[],"jp-g-0720":[{"text":"私には父がまだ生きていると思えてならない。","translation":"I can't help thinking Father is still alive.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"164507","matchedSignature":"てならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0721":[],"jp-g-0722":[],"jp-g-0723":[],"jp-g-0724":[{"text":"彼女はただの子供にすぎない。","translation":"She is no more than a child.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"92162","matchedSignature":"にすぎない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0725":[{"text":"この町は山もあれば海もあります。","translation":"This town has both mountains and the sea.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼は知識もあれば経験もあります。","translation":"He has both knowledge and experience.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この案には良い面もあれば悪い面もあります。","translation":"This proposal has both good points and bad points.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0726":[{"text":"彼は単なる愚か者でしかない。","translation":"He is nothing but a fool.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"102280","matchedSignature":"でしかない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼はまだ未成年でしかない。","translation":"He is hardly more than a lad.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"110807","matchedSignature":"でしかない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0727":[{"text":"子供達は風船が欲しくてたまらない。","translation":"Kids really want balloons.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"168411","matchedSignature":"てたまらない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0728":[],"jp-g-0729":[],"jp-g-0730":[{"text":"行くにしろ行かないにしろ、連絡してください。","translation":"Whether you go or not, please let me know.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"本当であるにしろ嘘であるにしろ、確認が必要です。","translation":"Whether it is true or false, it needs to be checked.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"子どもにしろ大人にしろ、ルールは守るべきです。","translation":"Whether child or adult, everyone should follow the rules.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0731":[{"text":"顔はともかく、気立てはとてもいい子だよ。","translation":"Looks aside, she is very good-natured.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"183637","matchedSignature":"はともかく","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"冗談はともかく、頭痛は医者に診てもらうべきだ。","translation":"Joking aside, you ought to see a doctor about your headache.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"12574119","matchedSignature":"はともかく","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0732":[],"jp-g-0733":[{"text":"仕事やら家事やらで忙しいです。","translation":"I am busy with work, housework, and all sorts of things.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"うれしいやら恥ずかしいやらで、何も言えませんでした。","translation":"I was both happy and embarrassed and could not say anything.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"雨やら風やらで大変でした。","translation":"The rain, wind, and everything else made it difficult.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0734":[{"text":"しかしながら、彼の言葉は全然信用されなかった。","translation":"His words, however, were not believed at all.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"216254","matchedSignature":"しかしながら","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"しかしながら、品物の数が誤っていました。","translation":"However, the quantity was not correct.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"216253","matchedSignature":"しかしながら","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"しかしながら、これらの溶剤は発がん性が指摘された。","translation":"However, these solvents were identified as carcinogenic.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"74542","matchedSignature":"しかしながら","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0735":[{"text":"彼が貧しいからといって不幸だということにはならない。","translation":"Just because he is poor, it does not follow that he is unhappy.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"119523","matchedSignature":"ことにはならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼が善良だからといって、賢いということにはならない。","translation":"Because he is good, it does not follow that he is wise.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"119692","matchedSignature":"ことにはならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼が金持ちだからといって、幸せだということにはならない。","translation":"Because he is rich, it doesn't follow that he is happy.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"120455","matchedSignature":"ことにはならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0736":[],"jp-g-0737":[],"jp-g-0738":[],"jp-g-0739":[{"text":"昨日はろくに寝ていません。","translation":"I barely slept yesterday.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"忙しくてろくに食事もできません。","translation":"I am so busy that I can hardly eat properly.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼は説明をろくに聞きませんでした。","translation":"He did not properly listen to the explanation.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0740":[],"jp-g-0741":[],"jp-g-0742":[],"jp-g-0743":[],"jp-g-0744":[{"text":"私達はいつも彼の忠告を取り入れるというわけではない。","translation":"We do not always take his advice.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"151845","matchedSignature":"というわけではない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"名声は必ずしも成功に付き物というわけではない。","translation":"Fame is not always an accompaniment of success.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"80795","matchedSignature":"というわけではない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼はいつも遅れてくるというわけではない。","translation":"He doesn't always come late.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"114484","matchedSignature":"というわけではない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0745":[],"jp-g-0746":[],"jp-g-0747":[],"jp-g-0748":[],"jp-g-0749":[],"jp-g-0750":[],"jp-g-0751":[{"text":"彼の態度は失礼極まりない。","translation":"His attitude is extremely rude.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"極まりない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、彼の態度は失礼極まりない。","translation":"In fact, his attitude is extremely rude.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"極まりない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「彼の態度は失礼極まりない」と言った。","translation":"A friend said, “His attitude is extremely rude.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"極まりない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0752":[{"text":"貧しいといえども彼女は幸せだ。","translation":"Though she is poor, she is happy.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"85200","matchedSignature":"といえども","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0753":[],"jp-g-0754":[{"text":"彼は人の話を最後まで聞かないきらいがある。","translation":"He has a tendency not to listen to people to the end.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"きらいがある","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、彼は人の話を最後まで聞かないきらいがある。","translation":"In fact, he has a tendency not to listen to people to the end.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"きらいがある","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「彼は人の話を最後まで聞かないきらいがある」と言った。","translation":"A friend said, “He has a tendency not to listen to people to the end.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"きらいがある","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0755":[],"jp-g-0756":[],"jp-g-0757":[{"text":"社会人ともなると、時間管理が重要になる。","translation":"Once you become a working adult, time management becomes important.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ともなると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、社会人ともなると、時間管理が重要になる。","translation":"In fact, once you become a working adult, time management becomes important.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ともなると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「社会人ともなると、時間管理が重要になる」と言った。","translation":"A friend said, “Once you become a working adult, time management becomes important.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ともなると","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0758":[{"text":"私が知らないのをいいことに彼は私をだました。","translation":"He took advantage of my ignorance and deceived me.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"167580","matchedSignature":"をいいことに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"お前が近くにいるのをいいことにベタベタしやがって！！","translation":"What the fuck are you up to taking advantage of his proximity to cling to him like a wet T-shirt?!","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"76811","matchedSignature":"をいいことに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0759":[],"jp-g-0760":[],"jp-g-0761":[],"jp-g-0762":[{"text":"大雨で試合の中止を余儀なくされた。","translation":"Heavy rain forced the game to be canceled.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"会社は計画の変更を余儀なくされた。","translation":"The company was forced to change its plan.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"けがのため引退を余儀なくされた。","translation":"The injury forced the person to retire.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0763":[],"jp-g-0764":[],"jp-g-0765":[{"text":"新学期が始まってからというもの、とっても忙しいの。","translation":"I've been very busy since the new term started.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"145301","matchedSignature":"てからというもの","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、新学期が始まってからというもの、とっても忙しいの。","translation":"In fact, i've been very busy since the new term started.","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"てからというもの","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「新学期が始まってからというもの、とっても忙しいの」と言った。","translation":"A friend said, “I've been very busy since the new term started.”","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"てからというもの","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0766":[],"jp-g-0767":[{"text":"東京公演を皮切りに、全国ツアーが始まった。","translation":"Beginning with the Tokyo performance, the nationwide tour started.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を皮切りに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、東京公演を皮切りに、全国ツアーが始まった。","translation":"In fact, beginning with the Tokyo performance, the nationwide tour started.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を皮切りに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「東京公演を皮切りに、全国ツアーが始まった」と言った。","translation":"A friend said, “Beginning with the Tokyo performance, the nationwide tour started.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を皮切りに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0768":[{"text":"彼は何でも詳しいが、料理に至っては全くできない。","translation":"He knows a lot about everything, but when it comes to cooking, he cannot do it at all.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に至っては","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、彼は何でも詳しいが、料理に至っては全くできない。","translation":"In fact, he knows a lot about everything, but when it comes to cooking, he cannot do it at all.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に至っては","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「彼は何でも詳しいが、料理に至っては全くできない」と言った。","translation":"A friend said, “He knows a lot about everything, but when it comes to cooking, he cannot do it at all.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に至っては","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0769":[],"jp-g-0770":[],"jp-g-0771":[],"jp-g-0772":[{"text":"雨が降ろうが降るまいが、試合は行います。","translation":"Whether it rains or not, the match will be held.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼が来ようが来るまいが、私は行きます。","translation":"Whether he comes or not, I will go.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"信じようが信じまいが、それが事実です。","translation":"Whether you believe it or not, that is the fact.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0773":[],"jp-g-0774":[],"jp-g-0775":[],"jp-g-0776":[],"jp-g-0777":[{"text":"この仕事を任せられるのは彼をおいてほかにない。","translation":"There is no one other than him to whom this job can be entrusted.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"をおいてほかに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、この仕事を任せられるのは彼をおいてほかにない。","translation":"In fact, there is no one other than him to whom this job can be entrusted.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"をおいてほかに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「この仕事を任せられるのは彼をおいてほかにない」と言った。","translation":"A friend said, “There is no one other than him to whom this job can be entrusted.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"をおいてほかに","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0778":[],"jp-g-0779":[],"jp-g-0780":[],"jp-g-0781":[],"jp-g-0782":[],"jp-g-0783":[],"jp-g-0784":[],"jp-g-0785":[],"jp-g-0786":[],"jp-g-0787":[],"jp-g-0788":[{"text":"新人にしてみれば、この仕事は難しいだろう。","translation":"From a newcomer’s point of view, this job is probably difficult.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"にしてみれば","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、新人にしてみれば、この仕事は難しいだろう。","translation":"In fact, from a newcomer’s point of view, this job is probably difficult.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"にしてみれば","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「新人にしてみれば、この仕事は難しいだろう」と言った。","translation":"A friend said, “From a newcomer’s point of view, this job is probably difficult.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"にしてみれば","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0789":[],"jp-g-0790":[],"jp-g-0791":[],"jp-g-0792":[],"jp-g-0793":[],"jp-g-0794":[],"jp-g-0795":[{"text":"二人は追いつ追われつ走り続けた。","translation":"The two kept running, alternately chasing and being chased.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼は廊下を行きつ戻りつしていた。","translation":"He was pacing back and forth along the hallway.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"小舟は波に浮きつ沈みつ進んだ。","translation":"The small boat moved along, rising and sinking with the waves.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0796":[],"jp-g-0797":[{"text":"子どもであれ大人であれ、参加できます。","translation":"Whether child or adult, anyone can participate.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"晴れであれ雨であれ、出発します。","translation":"Whether it is sunny or rainy, we will depart.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"賛成であれ反対であれ、意見を聞きたいです。","translation":"Whether you agree or disagree, I want to hear your opinion.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0798":[{"text":"秘密が漏れたら最後、信用は戻らない。","translation":"Once the secret leaks, trust will never return.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"たら最後","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、秘密が漏れたら最後、信用は戻らない。","translation":"In fact, once the secret leaks, trust will never return.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"たら最後","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「秘密が漏れたら最後、信用は戻らない」と言った。","translation":"A friend said, “Once the secret leaks, trust will never return.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"たら最後","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0799":[],"jp-g-0800":[],"jp-g-0801":[],"jp-g-0802":[{"text":"この町には歴史にまつわる伝説が多い。","translation":"This town has many legends connected with its history.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"にまつわる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、この町には歴史にまつわる伝説が多い。","translation":"In fact, this town has many legends connected with its history.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"にまつわる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「この町には歴史にまつわる伝説が多い」と言った。","translation":"A friend said, “This town has many legends connected with its history.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"にまつわる","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0803":[],"jp-g-0804":[{"text":"行くなら行くで、早く準備してください。","translation":"If you are going, then prepare quickly.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"買わないなら買わないで、先に言ってください。","translation":"If you are not going to buy it, say so beforehand.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"雨なら雨で、家で楽しめます。","translation":"If it rains, then we can enjoy ourselves at home in that case.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0805":[{"text":"氷のような水をものともせずに彼は川へ飛びこんだ。","translation":"He jumped into the river in defiance of the icy water.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"85394","matchedSignature":"をものともせず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"寒さをものともせずに、彼は薄着で外出した。","translation":"Making nothing of the cold, he went out in thin clothes.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"183999","matchedSignature":"をものともせず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0806":[],"jp-g-0807":[{"text":"計画は成功するものと思う。","translation":"I believe the plan will succeed.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ものと思う","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、計画は成功するものと思う。","translation":"In fact, i believe the plan will succeed.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ものと思う","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「計画は成功するものと思う」と言った。","translation":"A friend said, “I believe the plan will succeed.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ものと思う","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0808":[{"text":"調査結果を踏まえて、方針を見直した。","translation":"Based on the survey results, we reviewed the policy.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を踏まえて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、調査結果を踏まえて、方針を見直した。","translation":"In fact, based on the survey results, we reviewed the policy.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を踏まえて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「調査結果を踏まえて、方針を見直した」と言った。","translation":"A friend said, “Based on the survey results, we reviewed the policy.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を踏まえて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0809":[],"jp-g-0810":[],"jp-g-0811":[{"text":"影響は国内にとどまらず、海外にも広がった。","translation":"The impact was not limited to the country and spread overseas as well.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"にとどまらず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、影響は国内にとどまらず、海外にも広がった。","translation":"In fact, the impact was not limited to the country and spread overseas as well.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"にとどまらず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「影響は国内にとどまらず、海外にも広がった」と言った。","translation":"A friend said, “The impact was not limited to the country and spread overseas as well.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"にとどまらず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0812":[{"text":"簡単だと思いきや、意外に難しかった。","translation":"I thought it would be easy, but it was unexpectedly difficult.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"と思いきや","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、簡単だと思いきや、意外に難しかった。","translation":"In fact, i thought it would be easy, but it was unexpectedly difficult.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"と思いきや","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「簡単だと思いきや、意外に難しかった」と言った。","translation":"A friend said, “I thought it would be easy, but it was unexpectedly difficult.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"と思いきや","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0813":[],"jp-g-0814":[],"jp-g-0815":[],"jp-g-0816":[],"jp-g-0817":[{"text":"雨が降ったら降ったで、別の予定を立てましょう。","translation":"If it rains, then we will make a different plan.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"忙しかったら忙しかったで、やり方を変えます。","translation":"If it turns out to be busy, we will change how we do things.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"行けなかったら行けなかったで、仕方がありません。","translation":"If I cannot go, then that is how it is.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0818":[],"jp-g-0819":[],"jp-g-0820":[{"text":"遅かれ早かれ、結果は分かります。","translation":"Sooner or later, we will know the result.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"多かれ少なかれ、誰でも失敗します。","translation":"Everyone fails to a greater or lesser extent.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"良かれ悪しかれ、この決定は影響を与えます。","translation":"For better or worse, this decision will have an effect.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0821":[{"text":"本当のことを言うに言えません。","translation":"I want to tell the truth but cannot bring myself to say it.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"ここまで来たら引くに引けません。","translation":"Having come this far, I cannot back out even if I want to.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"悲しすぎて泣くに泣けませんでした。","translation":"I was so sad that I could not even cry.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0822":[],"jp-g-0823":[],"jp-g-0824":[{"text":"人質の運命はその交渉の結果にかかっている。","translation":"The fate of the hostages depends on the result of the negotiation.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"144197","matchedSignature":"にかかっている","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"万事はその結果いかんにかかっている。","translation":"Much depends upon the result.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"81107","matchedSignature":"にかかっている","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0825":[{"text":"皆様のご健康を願ってやまない。","translation":"I sincerely and unceasingly wish for everyone’s good health.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"てやまない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、皆様のご健康を願ってやまない。","translation":"In fact, i sincerely and unceasingly wish for everyone’s good health.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"てやまない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「皆様のご健康を願ってやまない」と言った。","translation":"A friend said, “I sincerely and unceasingly wish for everyone’s good health.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"てやまない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0826":[{"text":"他人のものを盗むぐらいなら死んだほうがましだ。","translation":"I would rather die than steal from others.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"138525","matchedSignature":"ぐらいなら","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"彼の下で働くぐらいなら私はむしろ餓死する。","translation":"I would rather starve than work under him.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"118015","matchedSignature":"ぐらいなら","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0827":[],"jp-g-0828":[],"jp-g-0829":[],"jp-g-0830":[],"jp-g-0831":[],"jp-g-0832":[],"jp-g-0833":[{"text":"訳あって、今は名前を言えません。","translation":"For certain reasons, I cannot say the name now.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"これは少し訳ありの商品です。","translation":"This is a product with some special circumstances or defects.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"訳ありで予定を変更しました。","translation":"We changed the schedule for certain reasons.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0834":[{"text":"問題が深刻化するに至って、ようやく対策が取られた。","translation":"Only after the problem became serious were measures finally taken.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に至って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、問題が深刻化するに至って、ようやく対策が取られた。","translation":"In fact, only after the problem became serious were measures finally taken.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に至って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「問題が深刻化するに至って、ようやく対策が取られた」と言った。","translation":"A friend said, “Only after the problem became serious were measures finally taken.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に至って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0835":[{"text":"そんな事故は想像だにしませんでした。","translation":"I never even imagined such an accident.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼が裏切るとは予想だにしませんでした。","translation":"I never even expected that he would betray us.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"その結果は考えだにしませんでした。","translation":"I never even considered that result.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0836":[],"jp-g-0837":[],"jp-g-0838":[{"text":"理由のいかんにかかわらず、遅刻は認めません。","translation":"Regardless of the reason, lateness is not accepted.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"年齢のいかんを問わず参加できます。","translation":"Anyone can participate regardless of age.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"結果のいかんによらず計画を続けます。","translation":"We will continue the plan regardless of the result.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0839":[],"jp-g-0840":[{"text":"この料理は辛くもなんともありません。","translation":"This dish is not spicy at all.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"その試験は難しくもなんともありませんでした。","translation":"That exam was not difficult at all.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"この荷物は重くもなんともありません。","translation":"This luggage is not heavy at all.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0841":[],"jp-g-0842":[{"text":"電話するなりメールするなりしてください。","translation":"Please either call or send an email.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"コーヒーなりお茶なり好きなものをどうぞ。","translation":"Please have coffee, tea, or whatever you like.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"休むなり病院に行くなりしたほうがいいです。","translation":"You should either rest or go to a hospital.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0843":[],"jp-g-0844":[{"text":"実際、失業問題もさることながら、環境問題も大切だ。","translation":"In fact, although the unemployment problem can't be ignored, the environment problem is also very important.","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"もさることながら","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0845":[{"text":"彼はもう帰ったものと思っていた。","translation":"I was under the impression that he had already gone home.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ものと思っていた","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、彼はもう帰ったものと思っていた。","translation":"In fact, i was under the impression that he had already gone home.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ものと思っていた","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「彼はもう帰ったものと思っていた」と言った。","translation":"A friend said, “I was under the impression that he had already gone home.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ものと思っていた","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0846":[],"jp-g-0847":[{"text":"細かい問題はさておき、まず全体の方針を決めよう。","translation":"Putting the small issues aside, let us first decide the overall policy.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"はさておき","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、細かい問題はさておき、まず全体の方針を決めよう。","translation":"In fact, putting the small issues aside, let us first decide the overall policy.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"はさておき","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「細かい問題はさておき、まず全体の方針を決めよう」と言った。","translation":"A friend said, “Putting the small issues aside, let us first decide the overall policy.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"はさておき","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0848":[],"jp-g-0849":[],"jp-g-0850":[{"text":"客は来るわ電話は鳴るわで、大忙しでした。","translation":"Customers kept coming and the phone kept ringing, so we were extremely busy.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"雨は降るわ風は吹くわで、大変でした。","translation":"It rained and the wind blew, one thing after another, so it was awful.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"値段は高いわ品質は悪いわで、最悪です。","translation":"It is expensive and the quality is bad—one problem after another.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0851":[],"jp-g-0852":[],"jp-g-0853":[{"text":"私達は時々、ドライブを兼ねて大好きなラーメンを食べに行きます。","translation":"We sometimes combine going for a drive with eating the ramen we love so.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"74420","matchedSignature":"を兼ねて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0854":[],"jp-g-0855":[],"jp-g-0856":[{"text":"努力と才能が相まって、大きな成果につながった。","translation":"Effort combined with talent led to a major achievement.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"相まって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、努力と才能が相まって、大きな成果につながった。","translation":"In fact, effort combined with talent led to a major achievement.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"相まって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「努力と才能が相まって、大きな成果につながった」と言った。","translation":"A friend said, “Effort combined with talent led to a major achievement.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"相まって","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0857":[{"text":"その年金では生活費に足りない。","translation":"The pension is not sufficient for living expenses.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"207285","matchedSignature":"に足りない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0858":[],"jp-g-0859":[],"jp-g-0860":[{"text":"規則に則って、手続きを進めてください。","translation":"Please proceed with the procedure in accordance with the rules.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に則って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、規則に則って、手続きを進めてください。","translation":"In fact, please proceed with the procedure in accordance with the rules.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に則って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「規則に則って、手続きを進めてください」と言った。","translation":"A friend said, “Please proceed with the procedure in accordance with the rules.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に則って","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0861":[],"jp-g-0862":[],"jp-g-0863":[{"text":"少しずつ春めいてきた。","translation":"It has gradually begun to feel like spring.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼は冗談めいた口調で話した。","translation":"He spoke in a joking sort of tone.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼女は謎めいた笑顔を見せた。","translation":"She gave a mysterious-looking smile.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0864":[],"jp-g-0865":[],"jp-g-0866":[{"text":"彼は何物にもまして名誉を重んじる。","translation":"He values honor above anything else.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"109315","matchedSignature":"にもまして","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"トムはいまや以前にもまして勤勉に働いている。","translation":"Tom works more diligently now.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"200110","matchedSignature":"にもまして","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0867":[],"jp-g-0868":[{"text":"客は来るわ電話は鳴るわで、大忙しでした。","translation":"Customers kept coming and the phone kept ringing, so we were extremely busy.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"雨は降るわ風は吹くわで、大変でした。","translation":"It rained and the wind blew, so it was awful.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"財布はなくすわ電車には遅れるわで、最悪でした。","translation":"I lost my wallet and missed the train; it was the worst.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0869":[],"jp-g-0870":[],"jp-g-0871":[],"jp-g-0872":[],"jp-g-0873":[],"jp-g-0874":[{"text":"あの日の暑さといったらなかった。","translation":"The heat that day was beyond description.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"彼の喜びようといったらなかった。","translation":"His joy was beyond words.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"試験前の忙しさといったらない。","translation":"The busyness before the exam is indescribable.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0875":[{"text":"過去の事例に照らして、慎重に判断した。","translation":"We judged carefully in light of past cases.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に照らして","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、過去の事例に照らして、慎重に判断した。","translation":"In fact, we judged carefully in light of past cases.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に照らして","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「過去の事例に照らして、慎重に判断した」と言った。","translation":"A friend said, “We judged carefully in light of past cases.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に照らして","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0876":[],"jp-g-0877":[],"jp-g-0878":[],"jp-g-0879":[],"jp-g-0880":[],"jp-g-0881":[],"jp-g-0882":[],"jp-g-0883":[],"jp-g-0884":[{"text":"現場の実情に即して、制度を見直す必要がある。","translation":"The system needs to be reviewed in line with actual conditions on the ground.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に即して","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、現場の実情に即して、制度を見直す必要がある。","translation":"In fact, the system needs to be reviewed in line with actual conditions on the ground.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に即して","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「現場の実情に即して、制度を見直す必要がある」と言った。","translation":"A friend said, “The system needs to be reviewed in line with actual conditions on the ground.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に即して","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0885":[],"jp-g-0886":[],"jp-g-0887":[{"text":"この問題は日本に限ったことではない。","translation":"This problem is not limited to Japan.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に限ったことではない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、この問題は日本に限ったことではない。","translation":"In fact, this problem is not limited to Japan.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に限ったことではない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「この問題は日本に限ったことではない」と言った。","translation":"A friend said, “This problem is not limited to Japan.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に限ったことではない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0888":[{"text":"今年の売上は去年とは比べものにならない。","translation":"This year’s sales are beyond comparison with last year’s.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"とは比べものにならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、今年の売上は去年とは比べものにならない。","translation":"In fact, this year’s sales are beyond comparison with last year’s.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"とは比べものにならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「今年の売上は去年とは比べものにならない」と言った。","translation":"A friend said, “This year’s sales are beyond comparison with last year’s.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"とは比べものにならない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0889":[],"jp-g-0890":[],"jp-g-0891":[],"jp-g-0892":[],"jp-g-0893":[{"text":"専門家に言わせれば、この対策では不十分だ。","translation":"According to an expert, these measures are insufficient.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に言わせれば","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、専門家に言わせれば、この対策では不十分だ。","translation":"In fact, according to an expert, these measures are insufficient.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に言わせれば","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「専門家に言わせれば、この対策では不十分だ」と言った。","translation":"A friend said, “According to an expert, these measures are insufficient.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に言わせれば","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0894":[],"jp-g-0895":[],"jp-g-0896":[],"jp-g-0897":[{"text":"外交の駆け引きでは、とても彼には及ばない。","translation":"I am no match for him in diplomatic shrewdness.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"184836","matchedSignature":"には及ばない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0898":[{"text":"春とは言うものの、朝晩はまだ寒い。","translation":"Although it is spring, mornings and evenings are still cold.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"とは言うものの","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、春とは言うものの、朝晩はまだ寒い。","translation":"In fact, although it is spring, mornings and evenings are still cold.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"とは言うものの","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「春とは言うものの、朝晩はまだ寒い」と言った。","translation":"A friend said, “Although it is spring, mornings and evenings are still cold.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"とは言うものの","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0899":[{"text":"ベルが鳴るが早いか、学生たちは教室を飛び出した。","translation":"As soon as the bell rang, the students rushed out of the classroom.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"が早いか","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、ベルが鳴るが早いか、学生たちは教室を飛び出した。","translation":"In fact, as soon as the bell rang, the students rushed out of the classroom.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"が早いか","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「ベルが鳴るが早いか、学生たちは教室を飛び出した」と言った。","translation":"A friend said, “As soon as the bell rang, the students rushed out of the classroom.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"が早いか","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0900":[{"text":"彼がどれほど苦労したかは想像に難くない。","translation":"It is not hard to imagine how much he struggled.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に難くない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、彼がどれほど苦労したかは想像に難くない。","translation":"In fact, it is not hard to imagine how much he struggled.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に難くない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「彼がどれほど苦労したかは想像に難くない」と言った。","translation":"A friend said, “It is not hard to imagine how much he struggled.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に難くない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0901":[{"text":"昔ならいざ知らず、今はＦＡＸも、メールもある。","translation":"I don't know about the past, but now we have faxes and emails.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"75944","matchedSignature":"ならいざ知らず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、昔ならいざ知らず、今はＦＡＸも、メールもある。","translation":"In fact, i don't know about the past, but now we have faxes and emails.","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"ならいざ知らず","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0902":[{"text":"その勇気には感動を禁じ得ない。","translation":"I cannot help but be moved by that courage.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を禁じ得ない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、その勇気には感動を禁じ得ない。","translation":"In fact, i cannot help but be moved by that courage.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を禁じ得ない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「その勇気には感動を禁じ得ない」と言った。","translation":"A friend said, “I cannot help but be moved by that courage.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を禁じ得ない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0903":[{"text":"愛国心にかこつけて多くの殺人が行われてきた。","translation":"Many murders have been committed in the name of patriotism.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"191535","matchedSignature":"にかこつけて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、愛国心にかこつけて多くの殺人が行われてきた。","translation":"In fact, many murders have been committed in the name of patriotism.","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"にかこつけて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「愛国心にかこつけて多くの殺人が行われてきた」と言った。","translation":"A friend said, “Many murders have been committed in the name of patriotism.”","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"にかこつけて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0904":[],"jp-g-0905":[{"text":"今から追いつくことは望むべくもない。","translation":"There is no hope of catching up now.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"べくもない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、今から追いつくことは望むべくもない。","translation":"In fact, there is no hope of catching up now.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"べくもない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「今から追いつくことは望むべくもない」と言った。","translation":"A friend said, “There is no hope of catching up now.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"べくもない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0906":[],"jp-g-0907":[],"jp-g-0908":[{"text":"全員が参加することを前提に、日程を決めた。","translation":"We set the schedule on the premise that everyone would participate.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を前提に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、全員が参加することを前提に、日程を決めた。","translation":"In fact, we set the schedule on the premise that everyone would participate.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を前提に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「全員が参加することを前提に、日程を決めた」と言った。","translation":"A friend said, “We set the schedule on the premise that everyone would participate.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"を前提に","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0909":[{"text":"これだけ迷惑をかけた以上、謝らずにはすまない。","translation":"After causing this much trouble, I have no choice but to apologize.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ずにはすまない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、これだけ迷惑をかけた以上、謝らずにはすまない。","translation":"In fact, after causing this much trouble, I have no choice but to apologize.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ずにはすまない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「これだけ迷惑をかけた以上、謝らずにはすまない」と言った。","translation":"A friend said, “After causing this much trouble, I have no choice but to apologize.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"ずにはすまない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0910":[{"text":"動物がいじめられているのは見るに堪えない。","translation":"I can't stand to see animals be teased.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"154832","matchedSignature":"に堪えない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、動物がいじめられているのは見るに堪えない。","translation":"In fact, i can't stand to see animals be teased.","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"に堪えない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「動物がいじめられているのは見るに堪えない」と言った。","translation":"A friend said, “I can't stand to see animals be teased.”","source":"AIDA context variation based on corpus example","source_id":null,"matchedSignature":"に堪えない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0911":[{"text":"注意を聞かず、最後には仕事まで失う始末だ。","translation":"He ignored the warnings and finally even ended up losing his job.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"始末だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、注意を聞かず、最後には仕事まで失う始末だ。","translation":"In fact, he ignored the warnings and finally even ended up losing his job.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"始末だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「注意を聞かず、最後には仕事まで失う始末だ」と言った。","translation":"A friend said, “He ignored the warnings and finally even ended up losing his job.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"始末だ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0912":[],"jp-g-0913":[{"text":"兄が活発なのにひきかえ、弟はおとなしい。","translation":"In sharp contrast to the active older brother, the younger brother is quiet.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"にひきかえ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、兄が活発なのにひきかえ、弟はおとなしい。","translation":"In fact, in sharp contrast to the active older brother, the younger brother is quiet.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"にひきかえ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「兄が活発なのにひきかえ、弟はおとなしい」と言った。","translation":"A friend said, “In sharp contrast to the active older brother, the younger brother is quiet.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"にひきかえ","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0914":[],"jp-g-0915":[{"text":"彼は慎重というか、臆病といおうか。","translation":"He is cautious, or perhaps I should say timid.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"といおうか","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、彼は慎重というか、臆病といおうか。","translation":"In fact, he is cautious, or perhaps I should say timid.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"といおうか","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「彼は慎重というか、臆病といおうか」と言った。","translation":"A friend said, “He is cautious, or perhaps I should say timid.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"といおうか","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0916":[],"jp-g-0917":[],"jp-g-0918":[{"text":"毎日こんなに暑くてはかなわない。","translation":"I cannot stand it being this hot every day.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"てはかなわない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、毎日こんなに暑くてはかなわない。","translation":"In fact, i cannot stand it being this hot every day.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"てはかなわない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「毎日こんなに暑くてはかなわない」と言った。","translation":"A friend said, “I cannot stand it being this hot every day.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"てはかなわない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0919":[],"jp-g-0920":[{"text":"事故は会社に計画の変更を余儀なくさせた。","translation":"The accident forced the company to change its plan.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"人手不足が店に営業時間の短縮を余儀なくさせた。","translation":"The labor shortage forced the shop to shorten its business hours.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"急な規則変更が多くの企業に対応を余儀なくさせた。","translation":"The sudden rule change forced many companies to respond.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0921":[],"jp-g-0922":[{"text":"今はただ待つのみです。","translation":"All we can do now is wait.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"あとはただ結果を信じるのみです。","translation":"All that remains is to trust the result.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"私たちはただ前に進むのみです。","translation":"All we can do is move forward.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0923":[{"text":"乙が受託業務の実施により得た成果は、甲乙双方に帰属するものとする。","translation":"Any result obtained through the execution of the Commissioned Business shall belong to each party hereto.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"188415","matchedSignature":"ものとする","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"第６条議長は全会議を主宰するものとする。","translation":"Article 6. The president shall preside at all meetings.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"137209","matchedSignature":"ものとする","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"製品仕様にかかわる一切の工業所有権はＡＢＣ社に帰属するものとする。","translation":"Any industrial property rights relating to the Product Specification shall belong to ABC Inc.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"142627","matchedSignature":"ものとする","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0924":[],"jp-g-0925":[],"jp-g-0926":[{"text":"大学の教授ともあろうものが、なぜ殺人事件を起こしたのだろうか。","translation":"Why would a university lecturer of all people end up responsible for a murder?","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"75899","matchedSignature":"ともあろう","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0927":[],"jp-g-0928":[],"jp-g-0929":[{"text":"新製品は世界発売に先駆けて、日本で公開された。","translation":"The new product was unveiled in Japan ahead of its worldwide release.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に先駆けて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、新製品は世界発売に先駆けて、日本で公開された。","translation":"In fact, the new product was unveiled in Japan ahead of its worldwide release.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に先駆けて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「新製品は世界発売に先駆けて、日本で公開された」と言った。","translation":"A friend said, “The new product was unveiled in Japan ahead of its worldwide release.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"に先駆けて","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0930":[],"jp-g-0931":[{"text":"よし、行くぞ！","translation":"All right, let's go!","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今から始めるぞ！","translation":"We're starting now!","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"絶対に勝つぞ！","translation":"We're definitely going to win!","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0932":[{"text":"一緒に行こうぜ。","translation":"Let's go together.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"もう帰るぜ。","translation":"I'm heading home now.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"これで決まりだぜ。","translation":"That settles it.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0933":[{"text":"ほんとにきれいだわ。","translation":"It really is beautiful.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"もう知らないわ。","translation":"I don't care anymore.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今日は本当に疲れたわ。","translation":"I'm really tired today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0934":[{"text":"何してるんだい？","translation":"What are you doing?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"どうしたんだい？","translation":"What's wrong?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"本当に行くのかい？","translation":"Are you really going?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0935":[{"text":"何してんの？","translation":"What are you doing?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"もう帰んの？","translation":"Are you going home already?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"そんなこと言ってんの？","translation":"Are you saying something like that?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0936":[{"text":"あいつ、今日は来ないっつってたよ。","translation":"He said he wasn't coming today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今、何っつった？","translation":"What did you just say?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"だから違うっつってんだろ。","translation":"I'm telling you, that's not it.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0937":[],"jp-g-0938":[],"jp-g-0939":[],"jp-g-0940":[],"jp-g-0941":[],"jp-g-0942":[{"text":"あわよくば、優勝まで狙いたい。","translation":"If luck is on my side, I would like to aim for the championship.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"あわよくば","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"実際、あわよくば、優勝まで狙いたい。","translation":"In fact, if luck is on my side, I would like to aim for the championship.","source":"AIDA original grammar example","source_id":null,"matchedSignature":"あわよくば","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"},{"text":"友達は「あわよくば、優勝まで狙いたい」と言った。","translation":"A friend said, “If luck is on my side, I would like to aim for the championship.”","source":"AIDA original grammar example","source_id":null,"matchedSignature":"あわよくば","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}],"jp-g-0943":[],"jp-g-0944":[{"text":"ほんまにええ店や。","translation":"It is a really good shop. (Kansai)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今日は休みや。","translation":"Today is a day off. (Kansai)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"あの人は先生や。","translation":"That person is a teacher. (Kansai)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0945":[{"text":"ほんまにうまいで。","translation":"It is really delicious, you know. (Kansai)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"明日は休みやで。","translation":"Tomorrow is a day off, you know. (Kansai)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"これ、ほんまにええわ。","translation":"This is really good. (Kansai)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0946":[],"jp-g-0947":[],"jp-g-0948":[],"jp-g-0949":[{"text":"ほんまに暑いな。","translation":"It is really hot, isn't it? (Kansai)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"これ、ええ感じやな。","translation":"This feels nice, doesn't it? (Kansai)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"明日も来るんやな。","translation":"You're coming tomorrow too, right? (Kansai)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0950":[],"jp-g-0951":[],"jp-g-0952":[],"jp-g-0953":[],"jp-g-0954":[],"jp-g-0955":[],"jp-g-0956":[{"text":"はよ食べぇ！","translation":"Eat quickly! (Kansai-style imperative)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"こっち見ぃ！","translation":"Look over here! (Kansai-style imperative)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"もう行きぃ！","translation":"Go already! (Kansai-style imperative)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0957":[],"jp-g-0958":[{"text":"そない急ぎな。","translation":"Don't rush like that. (Kansai-style prohibitive)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"無理しなや。","translation":"Don't overdo it. (Kansai-style prohibitive)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"気にしな。","translation":"Don't worry about it. (Kansai-style prohibitive)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0959":[],"jp-g-0960":[{"text":"そろそろ行こ。","translation":"Let's get going. (Kansai/colloquial volitional)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"一緒に食べよ。","translation":"Let's eat together. (Kansai/colloquial volitional)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"あとで見よ。","translation":"Let's look later. (Kansai/colloquial volitional)","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0961":[],"jp-g-0962":[],"jp-g-0963":[{"text":"もっと早く歩いて。","translation":"Walk faster.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"},{"text":"野菜を小さく切ってください。","translation":"Please cut the vegetables into small pieces.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"},{"text":"部屋を明るくした。","translation":"I made the room brighter.","source":"AIDA manually audited grammar example","auditVerified":true,"qualityStatus":"audited"}],"jp-g-0964":[{"text":"列車の遅れを見込んでおかないといけない。","translation":"We have to allow for the delay of the train.","source":"Tatoeba / Tanaka-WWWJDIC","source_id":"77536","matchedSignature":"ないといけない","qualityStatus":"corpus","verification":"exact-token-boundary + English-meaning match"}]}},"cantonese":{"vocabulary":{"yue-ev-0001":[{"text":"我今晚炒椰菜，加少少蒜頭就夠。","reading":"ngo5 gam1 maan5 caau2 je4 coi3, gaa1 siu2 siu2 syun3 tau4 zau6 gau3.","translation":"I'm stir-frying cabbage tonight; a little garlic is enough.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0002":[{"text":"我買咗兩個番薯，打算聽日焗嚟食。","reading":"ngo5 maai5 zo2 loeng5 go3 faan1 syu2, daa2 syun3 ting1 jat6 guk6 lai4 sik6.","translation":"I bought two sweet potatoes and plan to roast them tomorrow.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0003":[{"text":"白蘿蔔煲湯煲耐啲會甜好多。","reading":"baak6 lo4 baak6 bou1 tong1 bou1 noi6 di1 wui5 tim4 hou2 do1.","translation":"Daikon becomes much sweeter when it simmers in soup for longer.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0004":[{"text":"打邊爐嗰陣，我最鍾意食吸晒湯底味嘅大白菜。","reading":"daa2 bin1 lou4 go2 zan6, ngo5 zeoi3 zung1 ji3 sik6 kap1 saai3 tong1 dai2 mei6 ge3 daai6 baak6 coi3.","translation":"When I have hot pot, I especially like Chinese cabbage that has soaked up the broth.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0005":[{"text":"菠菜灼一陣就熟，唔使煮太耐。","reading":"bo1 coi3 zoek3 jat1 zan6 zau6 suk6, m4 sai2 zyu2 taai3 noi6.","translation":"Spinach cooks after a quick blanch, so you do not need to cook it for long.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0006":[{"text":"我切咗條青瓜整涼拌。","reading":"ngo5 cit3 zo2 tiu4 ceng1 gwaa1 zing2 loeng4 bun6.","translation":"I sliced a cucumber to make a cold salad.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0007":[{"text":"茄子吸油，所以我今次改用蒸嘅。","reading":"ke2 zi2 kap1 jau4, so2 ji5 ngo5 gam1 ci3 goi2 jung6 zing1 ge3.","translation":"Eggplant absorbs oil, so this time I decided to steam it instead.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0008":[{"text":"我將青椒切絲同牛肉一齊炒。","reading":"ngo5 zoeng1 ceng1 ziu1 cit3 si1 tung4 ngau4 juk6 jat1 cai4 caau2.","translation":"I sliced the green pepper into strips and stir-fried it with beef.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0009":[{"text":"紅色甜椒切開之後好甜。","reading":"hung4 sik1 tim4 ziu1 cit3 hoi1 zi1 hau6 hou2 tim4.","translation":"The red bell pepper tastes very sweet after you cut it open.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0010":[{"text":"椰菜花焗到邊位有少少焦最好食。","reading":"je4 coi3 faa1 guk6 dou3 bin1 wai2 jau5 siu2 siu2 ziu1 zeoi3 hou2 sik6.","translation":"Cauliflower tastes best when the edges are roasted until slightly browned.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0011":[{"text":"呢個南瓜好粉，用嚟煮湯好啱。","reading":"ni1 go3 naam4 gwaa1 hou2 fan2, jung6 lai4 zyu2 tong1 hou2 ngaam1.","translation":"This pumpkin has a nice starchy texture and is great for soup.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0012":[{"text":"落蒜頭爆香先再炒菜。","reading":"lok6 syun3 tau4 baau6 hoeng1 sin1 zoi3 caau2 coi3.","translation":"Fry the garlic until fragrant before adding the vegetables.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0013":[{"text":"金菇切走個根先放落鍋。","reading":"gam1 gu1 cit3 zau2 go3 gan1 sin1 fong3 lok6 wo1.","translation":"Cut off the base of the enoki mushrooms before putting them into the pot.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0014":[{"text":"芽菜炒太耐就唔脆。","reading":"ngaa4 coi3 caau2 taai3 noi6 zau6 m4 ceoi3.","translation":"Bean sprouts lose their crunch if you stir-fry them for too long.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0015":[{"text":"牛蒡切開之後好快變色。","reading":"ngau4 bong2 cit3 hoi1 zi1 hau6 hou2 faai3 bin3 sik1.","translation":"Burdock root changes color quickly after it is cut.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0016":[{"text":"蓮藕切片煲湯，口感仲有少少脆。","reading":"lin4 ngau5 cit3 pin2 bou1 tong1, hau2 gam2 zung6 jau5 siu2 siu2 ceoi3.","translation":"When lotus root is sliced and used in soup, it still keeps a slight crunch.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0017":[{"text":"秋葵灼熟之後切粒拌飯。","reading":"cau1 kwai4 zoek3 suk6 zi1 hau6 cit3 nap1 bun6 faan6.","translation":"After blanching the okra, I cut it into pieces and mixed it with rice.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0018":[{"text":"我哋叫咗碟毛豆，一路傾偈一路食。","reading":"ngo5 dei6 giu3 zo2 dip6 mou4 dau6, jat1 lou6 king1 gai2 jat1 lou6 sik6.","translation":"We ordered a plate of edamame and ate it while chatting.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0019":[{"text":"西芹切細粒放落炒飯幾香。","reading":"sai1 kan2 cit3 sai3 nap1 fong3 lok6 caau2 faan6 gei2 hoeng1.","translation":"Finely diced celery adds a nice aroma to fried rice.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0020":[{"text":"我用微波爐翻熱尋晚啲餸。","reading":"ngo5 jung6 mei4 bo1 lou4 faan1 jit6 cam4 maan5 di1 sung3.","translation":"I used the microwave to reheat last night's leftovers.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0021":[{"text":"電熱水壺一滾，我就沖咖啡。","reading":"din6 jit6 seoi2 wu4 jat1 gwan2, ngo5 zau6 cung1 gaa3 fe1.","translation":"As soon as the electric kettle boils, I make coffee.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0022":[{"text":"煎蛋用平底鑊會方便啲。","reading":"zin1 daan2 jung6 ping4 dai2 wok6 wui5 fong1 bin6 di1.","translation":"A frying pan is more convenient for frying eggs.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0023":[{"text":"你用湯勺幫我盛碗湯吖。","reading":"nei5 jung6 tong1 zoek3 bong1 ngo5 sing4 wun2 tong1 aa1.","translation":"Use the ladle to serve me a bowl of soup, please.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0024":[{"text":"炸嘢嗰陣用長筷子安全啲。","reading":"zaa3 je5 go2 zan6 jung6 coeng4 faai3 zi2 on1 cyun4 di1.","translation":"Long cooking chopsticks are safer when you are deep-frying food.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0025":[{"text":"冇開罐器，呢罐豆我開唔到。","reading":"mou5 hoi1 gun3 hei3, ni1 gun3 dau6 ngo5 hoi1 m4 dou2.","translation":"I cannot open this can of beans without a can opener.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0026":[{"text":"支汽水要用開瓶器先開到。","reading":"zi1 hei3 seoi2 jiu3 jung6 hoi1 ping4 hei3 sin1 hoi1 dou2.","translation":"This bottle of soda needs a bottle opener.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0027":[{"text":"食唔晒就放入保鮮盒，聽日再食。","reading":"sik6 m4 saai3 zau6 fong3 jap6 bou2 sin1 hap6, ting1 jat6 zoi3 sik6.","translation":"If you cannot finish it, put it in a food storage container and eat it tomorrow.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0028":[{"text":"我星期六朝早先開吸塵機，費事嘈到鄰居。","reading":"ngo5 sing1 kei4 luk6 ziu1 zou2 sin1 hoi1 kap1 can4 gei1, fai3 si6 cou4 dou3 leon4 geoi1.","translation":"I only turn on the vacuum cleaner on Saturday morning so I do not bother the neighbors.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0029":[{"text":"落足一日雨，我唯有用乾衣機。","reading":"lok6 zuk1 jat1 jat6 jyu5, ngo5 wai4 jau5 jung6 gon1 ji1 gei1.","translation":"It rained all day, so I had no choice but to use the clothes dryer.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0030":[{"text":"風太大，我將啲衫夾實喺晾衫竹上面。","reading":"fung1 taai3 daai6, ngo5 zoeng1 di1 saam1 gaap3 sat6 hai2 long6 saam1 zuk1 soeng6 min6.","translation":"The wind was strong, so I clipped the clothes securely to the clothesline pole.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0031":[{"text":"我加咗個層架，啲書終於唔使堆喺地下。","reading":"ngo5 gaa1 zo2 go3 cang4 gaa3, di1 syu1 zung1 jyu1 m4 sai2 deoi1 hai2 dei6 haa6.","translation":"I added a shelf, so the books finally do not have to be piled on the floor.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0032":[{"text":"隻兔仔一聽到袋聲就走過嚟。","reading":"zek3 tou3 zai2 jat1 teng1 dou3 doi2 seng1 zau6 zau2 gwo3 lai4.","translation":"The rabbit comes running over as soon as it hears the sound of the bag.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0033":[{"text":"天竺鼠食菜嗰陣會發出好細聲。","reading":"tin1 zuk1 syu2 sik6 coi3 go2 zan6 wui5 faat3 ceot1 hou2 sai3 seng1.","translation":"The guinea pig makes very soft sounds while eating vegetables.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0034":[{"text":"落完雨之後，附近啲青蛙叫得特別大聲。","reading":"lok6 jyun4 jyu5 zi1 hau6, fu6 gan6 di1 cing1 waa1 giu3 dak1 dak6 bit6 daai6 seng1.","translation":"After the rain, the frogs nearby call especially loudly.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0035":[{"text":"隻蜥蜴伏喺石上面曬太陽。","reading":"zek3 sik1 jik6 fuk6 hai2 sek6 soeng6 min6 saai3 taai3 joeng4.","translation":"The lizard is lying on a rock basking in the sun.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0036":[{"text":"有隻蝴蝶停咗喺窗邊。","reading":"jau5 zek3 wu4 dip6 ting4 zo2 hai2 coeng1 bin1.","translation":"A butterfly landed by the window.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0037":[{"text":"我哋搭渡輪過海，順便喺甲板吹風。","reading":"ngo5 dei6 daap3 dou6 leon4 gwo3 hoi2, seon6 bin6 hai2 gaap3 baan2 ceoi1 fung1.","translation":"We took the ferry across the harbor and enjoyed the breeze on deck.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0038":[{"text":"我出門口先發現冇帶充電器。","reading":"ngo5 ceot1 mun4 hau2 sin1 faat3 jin6 mou5 daai3 cung1 din6 hei3.","translation":"I only realized after leaving home that I had forgotten my charger.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0039":[{"text":"呢條USB線可以幫相機過相去電腦。","reading":"ni1 tiu4 ju1 e1 si4 bi1 sin3 ho2 ji5 bong1 soeng2 gei1 gwo3 soeng2 heoi3 din6 nou5.","translation":"This USB cable can transfer photos from the camera to the computer.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0040":[{"text":"坐長途機嗰陣，我會帶頭戴式耳機。","reading":"co5 coeng4 tou4 gei1 go2 zan6, ngo5 wui5 daai3 tau4 daai3 sik1 ji5 gei1.","translation":"I bring headphones when I take a long flight.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0041":[{"text":"我喺地鐵戴耳機聽節目。","reading":"ngo5 hai2 dei6 tit3 daai3 ji5 gei1 teng1 zit3 muk6.","translation":"I wear earphones on the subway to listen to shows.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0042":[{"text":"遙控器又跌咗落梳化底。","reading":"jiu4 hung3 hei3 jau6 dit3 zo2 lok6 so1 faa2 dai2.","translation":"The remote control fell under the sofa again.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0043":[{"text":"張枱附近冇插座，我部電腦就快冇電。","reading":"zoeng1 toi2 fu6 gan6 mou5 caap3 zo6, ngo5 bou6 din6 nou5 zau6 faai3 mou5 din6.","translation":"There is no outlet near the table, and my laptop is almost out of battery.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0044":[{"text":"去旅行我一定會帶外置充電器。","reading":"heoi3 leoi5 hang4 ngo5 jat1 ding6 wui5 daai3 ngoi6 zi3 cung1 din6 hei3.","translation":"I always bring a power bank when I travel.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0045":[{"text":"呢隻滑鼠個滾輪壞咗。","reading":"ni1 zek3 waat6 syu2 go3 gwan2 leon4 waai6 zo2.","translation":"The scroll wheel on this mouse is broken.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0046":[{"text":"我啲頭髮好乾，所以沖涼會用護髮素。","reading":"ngo5 di1 tau4 faat3 hou2 gon1, so2 ji5 cung1 loeng4 wui5 jung6 wu6 faat3 sou3.","translation":"My hair is very dry, so I use conditioner when I shower.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0047":[{"text":"呢支沐浴露陣味太濃。","reading":"ni1 zi1 muk6 juk6 lou6 zan6 mei6 taai3 nung4.","translation":"The scent of this body wash is too strong.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0048":[{"text":"我用肥皂洗完手先食嘢。","reading":"ngo5 jung6 fei4 zou6 sai2 jyun4 sau2 sin1 sik6 je5.","translation":"I wash my hands with soap before eating.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}],"yue-ev-0049":[{"text":"我個剃鬚刀鈍咗，要換刀片。","reading":"ngo5 go3 tai3 sou1 dou1 deon6 zo2, jiu3 wun6 dou1 pin2.","translation":"My razor has become dull, so I need to replace the blade.","source":"AIDA item-specific everyday context","qualityStatus":"curated"}]},"grammar":{"yue-g-012":[{"text":"我寄咗封信畀朋友。","reading":"ngo5 gei3 zo2 fung1 seon3 bei2 pang4 jau5.","translation":"I mailed a letter to a friend.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢攞咗杯水畀阿媽。","reading":"keoi5 lo2 zo2 bui1 seoi2 bei2 aa3 maa1.","translation":"He brought a glass of water to his mother.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我留咗個位畀你。","reading":"ngo5 lau4 zo2 go3 wai2 bei2 nei5.","translation":"I saved a seat for you.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-014":[{"text":"我唔食辣嘢。","reading":"ngo5 m4 sik6 laat6 je5.","translation":"I do not eat spicy food.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今日唔凍。","reading":"gam1 jat6 m4 dung3.","translation":"It is not cold today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢唔飲咖啡。","reading":"keoi5 m4 jam2 gaa3 fe1.","translation":"He does not drink coffee.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-031":[{"text":"我諗極都諗唔明。","reading":"ngo5 nam2 gik6 dou1 nam2 m4 ming4.","translation":"No matter how much I think about it, I still cannot understand it.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我搵極都搵唔到條鎖匙。","reading":"ngo5 wan2 gik6 dou1 wan2 m4 dou2 tiu4 so2 si4.","translation":"No matter how much I search, I cannot find the key.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢試極都唔成功。","reading":"keoi5 si3 gik6 dou1 m4 sing4 gung1.","translation":"No matter how many times he tries, he does not succeed.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-032":[{"text":"佢食親辣嘢都肚痛。","reading":"keoi5 sik6 can1 laat6 je5 dou1 tou5 tung3.","translation":"Every time he eats spicy food, his stomach hurts.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我飲親咖啡都瞓唔著。","reading":"ngo5 jam2 can1 gaa3 fe1 dou1 fan3 m4 zoek6.","translation":"Whenever I drink coffee, I cannot fall asleep.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢去親嗰間舖頭都要排隊。","reading":"keoi5 heoi3 can1 go2 gaan1 pou3 tau4 dou1 jiu3 paai4 deoi6.","translation":"Every time he goes to that shop, he has to queue.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-033":[{"text":"個細路突然喊起上嚟。","reading":"go3 sai3 lou6 dat6 jin4 haam3 hei2 soeng5 lei4.","translation":"The child suddenly started crying.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"大家聽完之後笑起上嚟。","reading":"daai6 gaa1 teng1 jyun4 zi1 hau6 siu3 hei2 soeng5 lei4.","translation":"After hearing it, everyone started laughing.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"出面忽然落起雨上嚟。","reading":"ceot1 min6 fat1 jin4 lok6 hei2 jyu5 soeng5 lei4.","translation":"It suddenly started raining outside.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-035":[{"text":"我喺屋企做功課。","reading":"ngo5 hai2 uk1 kei2 zou6 gung1 fo3.","translation":"I do homework at home.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢喺公司食晏。","reading":"keoi5 hai2 gung1 si1 sik6 ngaan3.","translation":"She eats lunch at the office.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我哋喺星期日見面。","reading":"ngo5 dei6 hai2 sing1 kei4 jat6 gin3 min6.","translation":"We will meet on Sunday.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-036":[{"text":"我同朋友食飯。","reading":"ngo5 tung4 pang4 jau5 sik6 faan6.","translation":"I eat with a friend.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢同家姐去行街。","reading":"keoi5 tung4 gaa1 ze1 heoi3 haang4 gaai1.","translation":"She goes shopping with her older sister.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我同同事開會。","reading":"ngo5 tung4 tung4 si6 hoi1 wui2.","translation":"I have a meeting with my colleagues.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-037":[{"text":"我同佢講咗件事。","reading":"ngo5 tung4 keoi5 gong2 zo2 gin6 si6.","translation":"I told him about the matter.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"老師同學生解釋個問題。","reading":"lou5 si1 tung4 hok6 saang1 gaai2 sik1 go3 man6 tai4.","translation":"The teacher explains the problem to the students.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢同我道歉。","reading":"keoi5 tung4 ngo5 dou6 hip3.","translation":"He apologized to me.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-038":[{"text":"我同你問下佢啦。","reading":"ngo5 tung4 nei5 man6 haa5 keoi5 laa1.","translation":"I will ask him for you.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我同你買埋早餐。","reading":"ngo5 tung4 nei5 maai5 maai4 zou2 caan1.","translation":"I will buy breakfast for you too.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"等我同阿媽攞藥。","reading":"dang2 ngo5 tung4 aa3 maa1 lo2 joek6.","translation":"Let me get the medicine for Mum.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-039":[{"text":"佢向老師道歉。","reading":"keoi5 hoeng3 lou5 si1 dou6 hip3.","translation":"He apologized to the teacher.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我對住塊鏡練習講嘢。","reading":"ngo5 deoi3 zyu6 faai3 geng3 lin6 zaap6 gong2 je5.","translation":"I practice speaking toward a mirror.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"架巴士向市中心開。","reading":"gaa3 baa1 si2 hoeng3 si5 zung1 sam1 hoi1.","translation":"The bus heads toward the city center.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-041":[{"text":"我都想去。","reading":"ngo5 dou1 soeng2 heoi3.","translation":"I want to go too.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"呢啲都好平。","reading":"ni1 di1 dou1 hou2 peng4.","translation":"These are all inexpensive.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"大家都識佢。","reading":"daai6 gaa1 dou1 sik1 keoi5.","translation":"Everyone knows him.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-048":[{"text":"佢講得好清楚。","reading":"keoi5 gong2 dak1 hou2 cing1 co2.","translation":"She speaks very clearly.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我行得太快。","reading":"ngo5 haang4 dak1 taai3 faai3.","translation":"I walk too quickly.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"你寫得好靚。","reading":"nei5 se2 dak1 hou2 leng3.","translation":"You write beautifully.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-051":[{"text":"我哋笑到肚痛。","reading":"ngo5 dei6 siu3 dou3 tou5 tung3.","translation":"We laughed so much that our stomachs hurt.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢攰到瞓著咗。","reading":"keoi5 gui6 dou3 fan3 zoek6 zo2.","translation":"He was so tired that he fell asleep.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我忙到冇時間食飯。","reading":"ngo5 mong4 dou3 mou5 si4 gaan3 sik6 faan6.","translation":"I am so busy that I have no time to eat.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-054":[{"text":"佢畀老闆鬧咗一餐。","reading":"keoi5 bei2 lou5 baan2 naau6 zo2 jat1 caan1.","translation":"He got a thorough scolding from the boss.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我哋琴晚笑咗一餐。","reading":"ngo5 dei6 kam4 maan5 siu3 zo2 jat1 caan1.","translation":"We had a long bout of laughter last night.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"個細路喊咗一餐先肯瞓。","reading":"go3 sai3 lou6 haam3 zo2 jat1 caan1 sin1 hang2 fan3.","translation":"The child cried for a long while before agreeing to sleep.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-055":[{"text":"我叫咗佢兩聲。","reading":"ngo5 giu3 zo2 keoi5 loeng5 seng1.","translation":"I called out to him twice.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢咳咗三聲。","reading":"keoi5 kat1 zo2 saam1 seng1.","translation":"She coughed three times.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"有人敲咗兩聲門。","reading":"jau5 jan4 haau1 zo2 loeng5 seng1 mun4.","translation":"Someone knocked on the door twice.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-056":[{"text":"我望咗佢一眼。","reading":"ngo5 mong6 zo2 keoi5 jat1 ngaan5.","translation":"I glanced at him once.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢踢咗個波一腳。","reading":"keoi5 tek3 zo2 go3 bo1 jat1 goek3.","translation":"He kicked the ball once.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢打咗沙包一拳。","reading":"keoi5 daa2 zo2 saa1 baau1 jat1 kyun4.","translation":"He punched the punching bag once.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-058":[{"text":"我攞本書畀佢睇。","reading":"ngo5 lo2 bun2 syu1 bei2 keoi5 tai2.","translation":"I brought a book for him to read.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我煮碗麵畀你食。","reading":"ngo5 zyu2 wun2 min6 bei2 nei5 sik6.","translation":"I will cook a bowl of noodles for you to eat.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢開段錄音畀我聽。","reading":"keoi5 hoi1 dyun6 luk6 jam1 bei2 ngo5 teng1.","translation":"She played a recording for me to listen to.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-064":[{"text":"我好開心。","reading":"ngo5 hou2 hoi1 sam1.","translation":"I am very happy.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢鍾意聽音樂。","reading":"keoi5 zung1 ji3 teng1 jam1 ngok6.","translation":"She likes listening to music.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"呢個方法好有用。","reading":"ni1 go3 fong1 faat3 hou2 jau5 jung6.","translation":"This method is very useful.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-069":[{"text":"件衫紅紅哋。","reading":"gin6 saam1 hung4 hung4 dei2.","translation":"The shirt is somewhat reddish.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"杯茶甜甜哋。","reading":"bui1 caa4 tim4 tim4 dei2.","translation":"The tea is a little sweet.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今日凍凍哋。","reading":"gam1 jat6 dung3 dung3 dei2.","translation":"It is a little chilly today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-072":[{"text":"我越學越有興趣。","reading":"ngo5 jyut6 hok6 jyut6 jau5 hing3 ceoi3.","translation":"The more I learn, the more interested I become.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢越講越快。","reading":"keoi5 jyut6 gong2 jyut6 faai3.","translation":"The more he speaks, the faster he gets.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"天氣越凍，我越唔想出街。","reading":"tin1 hei3 jyut6 dung3, ngo5 jyut6 m4 soeng2 ceot1 gaai1.","translation":"The colder the weather gets, the less I want to go out.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-075":[{"text":"你食飯未？","reading":"nei5 sik6 faan6 mei6?","translation":"Have you eaten yet?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"功課做完未？","reading":"gung1 fo3 zou6 jyun4 mei6?","translation":"Have you finished the homework yet?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢返到未？","reading":"keoi5 faan1 dou3 mei6?","translation":"Has he arrived back yet?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-076":[{"text":"你有冇時間？","reading":"nei5 jau5 mou5 si4 gaan3?","translation":"Do you have time?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"你有冇食早餐？","reading":"nei5 jau5 mou5 sik6 zou2 caan1?","translation":"Did you eat breakfast?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"呢度有冇洗手間？","reading":"ni1 dou6 jau5 mou5 sai2 sau2 gaan1?","translation":"Is there a restroom here?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-077":[{"text":"我坐呢度得唔得？","reading":"ngo5 co5 ni1 dou6 dak1 m4 dak1?","translation":"Is it okay if I sit here?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"聽日先交得唔得？","reading":"ting1 jat6 sin1 gaau1 dak1 m4 dak1?","translation":"Can I hand it in tomorrow instead?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"細聲啲講得唔得？","reading":"sai3 seng1 di1 gong2 dak1 m4 dak1?","translation":"Could you speak a little more quietly?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-096":[{"text":"我昨日買嘅書好好睇。","reading":"ngo5 zok6 jat6 maai5 ge3 syu1 hou2 hou2 tai2.","translation":"The book I bought yesterday is very good.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢整嘅蛋糕好香。","reading":"keoi5 zing2 ge3 daan6 gou1 hou2 hoeng1.","translation":"The cake she made smells great.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"企喺門口嘅人係我朋友。","reading":"kei5 hai2 mun4 hau2 ge3 jan4 hai6 ngo5 pang4 jau5.","translation":"The person standing at the door is my friend.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-102":[{"text":"我等咗兩個鐘。","reading":"ngo5 dang2 zo2 loeng5 go3 zung1.","translation":"I waited for two hours.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢尋晚瞓咗八粒鐘。","reading":"keoi5 cam4 maan5 fan3 zo2 baat3 nap1 zung1.","translation":"She slept for eight hours last night.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"車程要三個鐘。","reading":"ce1 cing4 jiu3 saam1 go3 zung1.","translation":"The journey takes three hours.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-001":[{"text":"我係學生。","reading":"ngo5 hai6 hok6 saang1.","translation":"I am a student.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢係我朋友。","reading":"keoi5 hai6 ngo5 pang4 jau5.","translation":"He is my friend.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"呢度係圖書館。","reading":"ni1 dou6 hai6 tou4 syu1 gun2.","translation":"This place is a library.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-002":[{"text":"我喺屋企。","reading":"ngo5 hai2 uk1 kei2.","translation":"I am at home.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢而家喺公司。","reading":"keoi5 ji4 gaa1 hai2 gung1 si1.","translation":"She is at the office now.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"本書喺枱面。","reading":"bun2 syu1 hai2 toi2 min6.","translation":"The book is on the table.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-003":[{"text":"今日好熱。","reading":"gam1 jat6 hou2 jit6.","translation":"It is very hot today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"呢間房好靜。","reading":"ni1 gaan1 fong2 hou2 zing6.","translation":"This room is very quiet.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢今日好忙。","reading":"keoi5 gam1 jat6 hou2 mong4.","translation":"She is very busy today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-004":[{"text":"我買咗一個好食嘅蛋糕。","reading":"ngo5 maai5 zo2 jat1 go3 hou2 sik6 ge3 daan6 gou1.","translation":"I bought a delicious cake.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢住喺一間好靜嘅屋。","reading":"keoi5 zyu6 hai2 jat1 gaan1 hou2 zing6 ge3 uk1.","translation":"She lives in a very quiet house.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我想搵啲平嘅衫。","reading":"ngo5 soeng2 wan2 di1 peng4 ge3 saam1.","translation":"I want to find some inexpensive clothes.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-005":[{"text":"我有兩個細佬。","reading":"ngo5 jau5 loeng5 go3 sai3 lou2.","translation":"I have two younger brothers.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"呢間房有冷氣。","reading":"ni1 gaan1 fong2 jau5 laang5 hei3.","translation":"This room has air conditioning.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢有時間幫你。","reading":"keoi5 jau5 si4 gaan3 bong1 nei5.","translation":"She has time to help you.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-007":[{"text":"呢本書係我嘅。","reading":"ni1 bun2 syu1 hai6 ngo5 ge3.","translation":"This book is mine.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我想要呢杯茶。","reading":"ngo5 soeng2 jiu3 ni1 bui1 caa4.","translation":"I want this cup of tea.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"呢個方法好簡單。","reading":"ni1 go3 fong1 faat3 hou2 gaan2 daan1.","translation":"This method is very simple.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-008":[{"text":"嗰個人係我老師。","reading":"go2 go3 jan4 hai6 ngo5 lou5 si1.","translation":"That person is my teacher.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我買咗嗰本書。","reading":"ngo5 maai5 zo2 go2 bun2 syu1.","translation":"I bought that book.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"嗰間餐廳今日休息。","reading":"go2 gaan1 caan1 teng1 gam1 jat6 jau1 sik1.","translation":"That restaurant is closed today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-009":[{"text":"我嘅手機冇電。","reading":"ngo5 ge3 sau2 gei1 mou5 din6.","translation":"My phone has no battery.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢嘅哥哥係醫生。","reading":"keoi5 ge3 go1 go1 hai6 ji1 sang1.","translation":"Her older brother is a doctor.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我哋嘅老師好有耐性。","reading":"ngo5 dei6 ge3 lou5 si1 hou2 jau5 noi6 sing3.","translation":"Our teacher is very patient.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-010":[{"text":"我哋聽日去旅行。","reading":"ngo5 dei6 ting1 jat6 heoi3 leoi5 hang4.","translation":"We are going on a trip tomorrow.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢哋已經到咗。","reading":"keoi5 dei6 ji5 ging1 dou3 zo2.","translation":"They have already arrived.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"你哋想食乜？","reading":"nei5 dei6 soeng2 sik6 mat1?","translation":"What do you all want to eat?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-015":[{"text":"我冇食早餐。","reading":"ngo5 mou5 sik6 zou2 caan1.","translation":"I did not eat breakfast.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢尋日冇返工。","reading":"keoi5 cam4 jat6 mou5 faan1 gung1.","translation":"She did not go to work yesterday.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我哋冇買飛。","reading":"ngo5 dei6 mou5 maai5 fei1.","translation":"We did not buy tickets.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-016":[{"text":"我未食飯。","reading":"ngo5 mei6 sik6 faan6.","translation":"I have not eaten yet.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢仲未到。","reading":"keoi5 zung6 mei6 dou3.","translation":"She still has not arrived.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我未睇嗰套戲。","reading":"ngo5 mei6 tai2 go2 tou3 hei3.","translation":"I have not watched that movie yet.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-017":[{"text":"唔係我唔想去，係我冇時間。","reading":"m4 hai6 ngo5 m4 soeng2 heoi3, hai6 ngo5 mou5 si4 gaan3.","translation":"It is not that I do not want to go; I do not have time.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"唔係佢做錯，係資料有問題。","reading":"m4 hai6 keoi5 zou6 co3, hai6 zi1 liu2 jau5 man6 tai4.","translation":"It is not that he did it wrong; the information has a problem.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我唔係話你一定要去。","reading":"ngo5 m4 hai6 waa6 nei5 jat1 ding6 jiu3 heoi3.","translation":"I am not saying that you definitely have to go.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-019":[{"text":"我食緊飯。","reading":"ngo5 sik6 gan2 faan6.","translation":"I am eating.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢睇緊電視。","reading":"keoi5 tai2 gan2 din6 si6.","translation":"She is watching television.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我哋等緊巴士。","reading":"ngo5 dei6 dang2 gan2 baa1 si2.","translation":"We are waiting for the bus.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-020":[{"text":"我喺度食緊飯。","reading":"ngo5 hai2 dou6 sik6 gan2 faan6.","translation":"I am here eating.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢喺度講緊電話。","reading":"keoi5 hai2 dou6 gong2 gan2 din6 waa2.","translation":"She is talking on the phone.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"你哋喺度做緊乜？","reading":"nei5 dei6 hai2 dou6 zou6 gan2 mat1?","translation":"What are you all doing?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-021":[{"text":"你攞住把遮。","reading":"nei5 lo2 zyu6 baa2 ze1.","translation":"You are holding an umbrella.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"道門開住。","reading":"dou6 mun4 hoi1 zyu6.","translation":"The door is being kept open.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢笑住同我講。","reading":"keoi5 siu3 zyu6 tung4 ngo5 gong2.","translation":"She spoke to me while smiling.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-022":[{"text":"我食開呢間茶餐廳。","reading":"ngo5 sik6 hoi1 ni1 gaan1 caa4 caan1 teng1.","translation":"I usually eat at this cha chaan teng.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢用開呢個牌子。","reading":"keoi5 jung6 hoi1 ni1 go3 paai4 zi2.","translation":"She habitually uses this brand.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"你睇開邊個頻道？","reading":"nei5 tai2 hoi1 bin1 go3 pan4 dou6?","translation":"Which channel do you usually watch?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-023":[{"text":"我去過日本。","reading":"ngo5 heoi3 gwo3 jat6 bun2.","translation":"I have been to Japan.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢食過蛇羹。","reading":"keoi5 sik6 gwo3 se4 gang1.","translation":"She has eaten snake soup before.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"你睇過呢套戲未？","reading":"nei5 tai2 gwo3 ni1 tou3 hei3 mei6?","translation":"Have you seen this movie before?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-024":[{"text":"我食咗飯。","reading":"ngo5 sik6 zo2 faan6.","translation":"I ate.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢返咗屋企。","reading":"keoi5 faan1 zo2 uk1 kei2.","translation":"She went home.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我哋買咗飛。","reading":"ngo5 dei6 maai5 zo2 fei1.","translation":"We bought the tickets.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-025":[{"text":"我食完飯先出門口。","reading":"ngo5 sik6 jyun4 faan6 sin1 ceot1 mun4 hau2.","translation":"I will go out after I finish eating.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢做完功課就瞓。","reading":"keoi5 zou6 jyun4 gung1 fo3 zau6 fan3.","translation":"She goes to sleep after finishing her homework.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"你睇完本書未？","reading":"nei5 tai2 jyun4 bun2 syu1 mei6?","translation":"Have you finished reading the book?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-026":[{"text":"佢食晒啲蛋糕。","reading":"keoi5 sik6 saai3 di1 daan6 gou1.","translation":"She ate all the cake.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我用晒啲錢。","reading":"ngo5 jung6 saai3 di1 cin2.","translation":"I used up all the money.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"啲飛賣晒喇。","reading":"di1 fei1 maai6 saai3 laa3.","translation":"All the tickets have sold out.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-027":[{"text":"你試吓呢個方法。","reading":"nei5 si3 haa5 ni1 go3 fong1 faat3.","translation":"Try this method.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"等我睇吓先。","reading":"dang2 ngo5 tai2 haa5 sin1.","translation":"Let me have a look first.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"入嚟坐吓啦。","reading":"jap6 lei4 co5 haa5 laa1.","translation":"Come in and sit for a while.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-028":[{"text":"你食埋先走啦。","reading":"nei5 sik6 maai4 sin1 zau2 laa1.","translation":"Finish eating this too before you leave.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我做埋呢份功課就休息。","reading":"ngo5 zou6 maai4 ni1 fan6 gung1 fo3 zau6 jau1 sik1.","translation":"I will rest after finishing this homework too.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"幫我買埋牛奶。","reading":"bong1 ngo5 maai5 maai4 ngau4 naai5.","translation":"Buy milk for me as well.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-029":[{"text":"我終於搵到鎖匙。","reading":"ngo5 zung1 jyu1 wan2 dou2 so2 si4.","translation":"I finally managed to find the key.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"你聽唔聽到我講嘢？","reading":"nei5 teng1 m4 teng1 dou2 ngo5 gong2 je5?","translation":"Can you hear me speaking?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我今日買到飛喇。","reading":"ngo5 gam1 jat6 maai5 dou2 fei1 laa3.","translation":"I managed to buy a ticket today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-030":[{"text":"你繼續講落去。","reading":"nei5 gai3 zuk6 gong2 lok6 heoi3.","translation":"Keep talking.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"再做落去會好攰。","reading":"zoi3 zou6 lok6 heoi3 wui5 hou2 gui6.","translation":"If you keep doing it, you will get very tired.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"個故事一路發展落去。","reading":"go3 gu3 si6 jat1 lou6 faat3 zin2 lok6 heoi3.","translation":"The story keeps developing.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-040":[{"text":"呢個活動由學校安排。","reading":"ni1 go3 wut6 dung6 jau4 hok6 haau6 on1 paai4.","translation":"This activity is arranged by the school.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"份報告由佢負責寫。","reading":"fan6 bou3 gou3 jau4 keoi5 fu6 zaak3 se2.","translation":"The report is written under his responsibility.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我哋由香港出發。","reading":"ngo5 dei6 jau4 hoeng1 gong2 ceot1 faat3.","translation":"We depart from Hong Kong.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-042":[{"text":"佢今日又遲到。","reading":"keoi5 gam1 jat6 jau6 ci4 dou3.","translation":"She is late again today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我又想食，又想瞓。","reading":"ngo5 jau6 soeng2 sik6, jau6 soeng2 fan3.","translation":"I want to eat, and I also want to sleep.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"今日又落雨。","reading":"gam1 jat6 jau6 lok6 jyu5.","translation":"It is raining again today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-043":[{"text":"我淨係想休息。","reading":"ngo5 zing6 hai6 soeng2 jau1 sik1.","translation":"I only want to rest.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢淨係飲水。","reading":"keoi5 zing6 hai6 jam2 seoi2.","translation":"She only drinks water.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我哋淨係去兩日。","reading":"ngo5 dei6 zing6 hai6 heoi3 loeng5 jat6.","translation":"We are only going for two days.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-044":[{"text":"佢仲做緊功課。","reading":"keoi5 zung6 zou6 gan2 gung1 fo3.","translation":"She is still doing homework.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我仲想問一個問題。","reading":"ngo5 zung6 soeng2 man6 jat1 go3 man6 tai4.","translation":"I still want to ask one more question.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"出面仲落緊雨。","reading":"ceot1 min6 zung6 lok6 gan2 jyu5.","translation":"It is still raining outside.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-045":[{"text":"你去，我就去。","reading":"nei5 heoi3, ngo5 zau6 heoi3.","translation":"If you go, then I will go.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"如果落雨，我哋就留喺屋企。","reading":"jyu4 gwo2 lok6 jyu5, ngo5 dei6 zau6 lau4 hai2 uk1 kei2.","translation":"If it rains, then we will stay at home.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"做完功課就可以休息。","reading":"zou6 jyun4 gung1 fo3 zau6 ho2 ji5 jau1 sik1.","translation":"Once the homework is finished, you can rest.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-046":[{"text":"我食完飯先走。","reading":"ngo5 sik6 jyun4 faan6 sin1 zau2.","translation":"I will leave only after I finish eating.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"你諗清楚先答。","reading":"nei5 nam2 cing1 co2 sin1 daap3.","translation":"Think it through before answering.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢十點先返到屋企。","reading":"keoi5 sap6 dim2 sin1 faan1 dou3 uk1 kei2.","translation":"She did not get home until ten.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-047":[{"text":"佢開心咁笑。","reading":"keoi5 hoi1 sam1 gam2 siu3.","translation":"She smiled happily.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"你慢慢咁講。","reading":"nei5 maan6 maan6 gam2 gong2.","translation":"Speak slowly.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"個細路靜靜咁行入房。","reading":"go3 sai3 lou6 zing6 zing6 gam2 haang4 jap6 fong2.","translation":"The child quietly walked into the room.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-049":[{"text":"你慢慢咁講。","reading":"nei5 maan6 maan6 gam2 gong2.","translation":"Speak slowly.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢靜靜咁坐喺度。","reading":"keoi5 zing6 zing6 gam2 co5 hai2 dou6.","translation":"She sat there quietly.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"你輕輕咁放低個杯。","reading":"nei5 hing1 hing1 gam2 fong3 dai1 go3 bui1.","translation":"Put the cup down gently.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-050":[{"text":"佢係咁講同一件事。","reading":"keoi5 hai6 gam2 gong2 tung4 jat1 gin6 si6.","translation":"She keeps talking about the same thing.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"個細路係咁喊。","reading":"go3 sai3 lou6 hai6 gam2 haam3.","translation":"The child keeps crying.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"出面啲雨係咁落。","reading":"ceot1 min6 di1 jyu5 hai6 gam2 lok6.","translation":"The rain outside keeps pouring down.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-052":[{"text":"我去過三次。","reading":"ngo5 heoi3 gwo3 saam1 ci3.","translation":"I have been there three times.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢問咗兩次。","reading":"keoi5 man6 zo2 loeng5 ci3.","translation":"She asked twice.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"呢套戲我睇咗五次。","reading":"ni1 tou3 hei3 ngo5 tai2 zo2 ng5 ci3.","translation":"I have watched this movie five times.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-053":[{"text":"等我睇一下。","reading":"dang2 ngo5 tai2 jat1 haa5.","translation":"Let me take a look.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"你試一下先。","reading":"nei5 si3 jat1 haa5 sin1.","translation":"Try it once first.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"請停一下。","reading":"cing2 ting4 jat1 haa5.","translation":"Please stop for a moment.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-071":[{"text":"天氣凍咗。","reading":"tin1 hei3 dung3 zo2.","translation":"The weather has become colder.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢瘦咗好多。","reading":"keoi5 sau3 zo2 hou2 do1.","translation":"She has become much thinner.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"呢度靜咗。","reading":"ni1 dou6 zing6 zo2.","translation":"It has become quieter here.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-074":[{"text":"係唔係你打畀我？","reading":"hai6 m4 hai6 nei5 daa2 bei2 ngo5?","translation":"Was it you who called me?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢係唔係聽日返嚟？","reading":"keoi5 hai6 m4 hai6 ting1 jat6 faan1 lei4?","translation":"Is she coming back tomorrow?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"呢個係唔係你想要嘅？","reading":"ni1 go3 hai6 m4 hai6 nei5 soeng2 jiu3 ge3?","translation":"Is this the one you want?","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-086":[{"text":"唔該畀杯水我。","reading":"m4 goi1 bei2 bui1 seoi2 ngo5.","translation":"Please give me a glass of water.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"唔該幫我開門。","reading":"m4 goi1 bong1 ngo5 hoi1 mun4.","translation":"Please help me open the door.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"唔該再講一次。","reading":"m4 goi1 zoi3 gong2 jat1 ci3.","translation":"Please say it one more time.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-087":[{"text":"唔該，幫我開門。","reading":"m4 goi1, bong1 ngo5 hoi1 mun4.","translation":"Please help me open the door.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"唔該晒你。","reading":"m4 goi1 saai3 nei5.","translation":"Thank you very much.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"多謝你今日幫我。","reading":"do1 ze6 nei5 gam1 jat6 bong1 ngo5.","translation":"Thank you for helping me today.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-088":[{"text":"對唔住，我遲到咗。","reading":"deoi3 m4 zyu6, ngo5 ci4 dou3 zo2.","translation":"Sorry, I was late.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"唔好意思，阻你一陣。","reading":"m4 hou2 ji3 si1, zo2 nei5 jat1 zan6.","translation":"Excuse me for taking up a moment of your time.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"真係對唔住。","reading":"zan1 hai6 deoi3 m4 zyu6.","translation":"I am really sorry.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-100":[{"text":"今日係二零二六年七月十一號。","reading":"gam1 jat6 hai6 ji6 ling4 ji6 luk6 nin4 cat1 jyut6 sap6 jat1 hou6.","translation":"Today is July 11, 2026.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"佢二零二五年十二月二十四號返香港。","reading":"keoi5 ji6 ling4 ji6 ng5 nin4 sap6 ji6 jyut6 ji6 sap6 sei3 hou6 faan1 hoeng1 gong2.","translation":"She returns to Hong Kong on December 24, 2025.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"會議改到二零二四年三月一號。","reading":"wui6 ji5 goi2 dou3 ji6 ling4 ji6 sei3 nin4 saam1 jyut6 jat1 hou6.","translation":"The meeting was moved to March 1, 2024.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}],"yue-g-101":[{"text":"而家三點十五分。","reading":"ji4 gaa1 saam1 dim2 sap6 ng5 fan1.","translation":"It is 3:15 now.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"會議八點三十分開始。","reading":"wui6 ji5 baat3 dim2 saam1 sap6 fan1 hoi1 ci2.","translation":"The meeting starts at 8:30.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"},{"text":"我十點四十五分返到屋企。","reading":"ngo5 sap6 dim2 sei3 sap6 ng5 fan1 faan1 dou3 uk1 kei2.","translation":"I get home at 10:45.","source":"AIDA audited grammar override","auditVerified":true,"qualityStatus":"audited"}]}}};
